export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null
): Promise<RCMItem[]> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable is not set.");
    }

    const ai = new GoogleGenAI({ apiKey });

    const parts: any[] = [];

    // Add file content if available
    if (fileData) {
      parts.push({
        inlineData: {
          mimeType: fileData.mimeType,
          data: fileData.data,
        },
      });
      parts.push({
        text: "Analyze the uploaded document/image containing operational context or technical specifications. Identify every sub-system and component."
      });
    }

    // Add manual text context
    if (contextText) {
      parts.push({
        text: `Operational Context provided by user:\n${contextText}`
      });
    }

    parts.push({
      text: `Perform an EXHAUSTIVE, high-granularity Reliability Centered Maintenance (RCM) and FMECA analysis. 

      MANDATORY REQUIREMENTS FOR EXHAUSTIVENESS:
      1. **Component Decomposition**: Identify and analyze the system down to the "Lowest Replaceable Unit" (LRU). Do not stop at the system level; look for seals, bearings, windings, connectors, fasteners, etc.
      2. **Diverse Failure Modes**: For EVERY component identified, you MUST brainstorm and list all applicable physical failure mechanisms including but not limited to: Fatigue, Corrosion, Erosion, Surface Wear, Brittle Fracture, Overheating, Seal degradation, Misalignment, and Electrical Insulation breakdown.
      3. **No Summarization**: Do not group multiple failure modes together. Every unique mechanism-cause pair must be a separate entry in the result array.
      4. **Task Matching**: Ensure every failure mode has a technically appropriate maintenance task. If a mode is 'Hidden', you MUST include Failure Finding tasks.
      5. **Failure Mode Formatting**: Strictly use "[Mechanism] due to [Cause]".
      6. **SAE JA1011 & ISO 14224**: Adhere rigidly to these standards for taxonomy and consequence classification.

      I want a long, comprehensive list that leaves no potential risk unaddressed. Even 'minor' or 'low occurrence' failure modes should be included if they are technically possible within this context.`
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: rcmSchema,
        seed: 42, // Ensures identical outputs for identical inputs
        thinkingConfig: {
          thinkingBudget: 16000 // Provides "reasoning room" to explore more failure modes before outputting JSON
        },
        systemInstruction: "You are a World-Class Senior Reliability Engineer specializing in deep FMECA decomposition. You are incredibly thorough and detailed. Your goal is to identify EVERY possible failure mode and maintenance requirement, no matter how small. Your output is exhaustive, technically rigorous, and consistent."
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response generated from Gemini.");
    }

    // Parse JSON and add ROBUST Unique IDs
    const rawData = JSON.parse(text) as Omit<RCMItem, 'id' | 'rpn'>[];

    return rawData.map((item, index) => ({ 
      ...item, 
      severity: item.severity || 5,
      occurrence: item.occurrence || 3,
      detection: item.detection || 3,
      rpn: (item.severity || 5) * (item.occurrence || 3) * (item.detection || 3),
      id: `rcm-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 9)}` 
    }));

  } catch (error) {
    console.error("RCM Generation Error:", error);
    throw error;
  }
};

