interface OperationalContextBuilderProps {
  isOpen: boolean;
  onClose: () => void;
  onComplete: (context: string) => void;
}

const STEPS = [
  { id: 'asset', label: 'Asset Info', icon: Settings },
  { id: 'env', label: 'Environment', icon: Thermometer },
  { id: 'duty', label: 'Duty Cycle', icon: Clock },
  { id: 'params', label: 'Parameters', icon: Activity },
  { id: 'history', label: 'History', icon: History }
];

export const OperationalContextBuilder: React.FC<OperationalContextBuilderProps> = ({ isOpen, onClose, onComplete }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState({
    assetName: '',
    assetType: '',
    criticality: 'Medium',
    temp: '',
    humidity: '',
    exposure: '',
    dutyCycle: 'Continuous',
    startupFreq: '',
    rpm: '',
    load: '',
    material: '',
    age: '',
    knownIssues: ''
  });

  if (!isOpen) return null;

  const handleNext = () => {
    if (currentStep < STEPS.length - 1) setCurrentStep(currentStep + 1);
    else finish();
  };

  const handleBack = () => {
    if (currentStep > 0) setCurrentStep(currentStep - 1);
  };

  const finish = () => {
    const summary = `
[ASSET IDENTIFICATION]
Asset: ${formData.assetName || 'Unspecified'} (${formData.assetType || 'Generic'})
Process Criticality: ${formData.criticality}

[OPERATING ENVIRONMENT]
Temperature: ${formData.temp || 'Standard'}
Humidity: ${formData.humidity || 'Standard'}
Exposure/Environment: ${formData.exposure || 'Clean indoor environment'}

[DUTY CYCLE & OPERATION]
Duty Cycle: ${formData.dutyCycle}
Startup Frequency: ${formData.startupFreq || 'Normal'}

[TECHNICAL PARAMETERS]
Operating Speed/Load: ${formData.rpm || 'N/A'} RPM / ${formData.load || 'N/A'}
Material Processed: ${formData.material || 'N/A'}

[ASSET HISTORY]
Age: ${formData.age || 'Unknown'}
Known Recurring Issues: ${formData.knownIssues || 'None reported'}
    `.trim();
    onComplete(summary);
    onClose();
  };

  const updateField = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-200">

        {/* Header */}
        <div className="bg-indigo-600 px-6 py-4 flex justify-between items-center text-white shrink-0">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-white/20 rounded-lg">
              <Settings size={20} className="text-white" />
            </div>
            <div>
              <h3 className="font-bold text-lg leading-none">Operational Context Builder</h3>
              <p className="text-xs text-indigo-100 mt-1">Structured data for high-fidelity analysis</p>
            </div>
          </div>
          <button onClick={onClose} className="hover:bg-white/10 p-2 rounded-full transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Stepper Progress */}
        <div className="flex border-b border-slate-100 bg-slate-50/50 px-6 py-3">
          {STEPS.map((step, idx) => {
            const Icon = step.icon;
            const isActive = currentStep === idx;
            const isCompleted = currentStep > idx;
            return (
              <div key={step.id} className="flex-1 flex items-center">
                <div className="flex flex-col items-center gap-1 group">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all border ${
                    isActive ? 'bg-indigo-600 text-white border-indigo-600 shadow-md scale-110' : 
                    isCompleted ? 'bg-emerald-500 text-white border-emerald-500' : 'bg-white text-slate-400 border-slate-200'
                  }`}>
                    {isCompleted ? <CheckCircle size={14} /> : idx + 1}
                  </div>
                  <span className={`text-[10px] font-bold uppercase tracking-tighter ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}>{step.label}</span>
                </div>
                {idx < STEPS.length - 1 && (
                  <div className={`flex-1 h-0.5 mx-2 rounded-full ${isCompleted ? 'bg-emerald-500' : 'bg-slate-200'}`} />
                )}
              </div>
            );
          })}
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-8 bg-white min-h-[350px]">
