                  {['Low', 'Medium', 'High'].map(level => (
                    <button key={level} onClick={() => updateField('criticality', level)} className={`flex-1 py-2 text-sm font-bold rounded-lg border transition-all ${formData.criticality === level ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-500 border-slate-200 hover:border-indigo-300'}`}>{level}</button>
