import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { MessageSquare, X, Send, Loader2, Bot, User, Sparkles, ChevronDown } from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
}

interface Message {
  role: 'user' | 'model';
  text: string;
}

export const AICopilot: React.FC<AICopilotProps> = ({ data }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const contextString = data ? JSON.stringify(data.map(i => ({
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        type: i.taskType,
        rpn: i.rpn
      }))) : "No analysis data available yet.";

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-lite-latest',
        contents: [
          { role: 'user', parts: [{ text: `You are a Senior Reliability Engineer. Context: ${contextString}\n\nUser Question: ${userMsg}` }] }
        ],
        config: {
          systemInstruction: "Assistant is an RCM expert. Provide concise, technically accurate advice based on SAE JA1011 standards. If referencing the current analysis, be specific about components and tasks mentioned in the context."
        }
      });

      const modelText = response.text || "I'm sorry, I couldn't generate a response.";
      setMessages(prev => [...prev, { role: 'model', text: modelText }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Error: Failed to connect to the reliability expert. Please check your connection." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[450px] h-[600px] bg-white rounded-2xl shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
          {/* Header */}
          <div className="bg-indigo-600 p-4 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-white/20 rounded-lg">
                <Bot size={20} />
              </div>
              <div>
                <h3 className="font-bold text-sm">Reliability Co-pilot</h3>
                <div className="flex items-center gap-1.5">
                   <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse"></div>
                   <span className="text-[10px] text-indigo-100 font-medium">Expert System Online</span>
                </div>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-colors">
              <ChevronDown size={20} />
            </button>
          </div>

          {/* Messages */}
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center">
                  <Sparkles size={24} />
                </div>
                <div>
                  <p className="text-sm font-bold text-slate-800">Ask your Reliability Expert</p>
                  <p className="text-xs text-slate-500 mt-1 leading-relaxed">
                    Ask about failure modes, maintenance strategies, or justification for the generated RCM tasks.
                  </p>
                </div>
                <div className="grid grid-cols-1 gap-2 w-full">
                  {['Why is CBM recommended here?', 'Explain this RPN score', 'How to improve reliability?'].map(q => (
                    <button 
                      key={q} 
                      onClick={() => { setInput(q); }}
                      className="text-[10px] font-bold text-slate-600 bg-white border border-slate-200 p-2 rounded-lg hover:border-indigo-300 hover:text-indigo-600 transition-all shadow-sm"
                    >
                      "{q}"
                    </button>
                  ))}
                </div>
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-xs leading-relaxed shadow-sm ${
                  m.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-br-none' 
                    : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none'
                }`}>
                  <div className="flex items-center gap-2 mb-1 opacity-70">
                    {m.role === 'user' ? <User size={10} /> : <Bot size={10} />}
                    <span className="text-[9px] font-bold uppercase tracking-wider">{m.role === 'user' ? 'You' : 'Expert'}</span>
                  </div>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-2">
                  <Loader2 size={14} className="animate-spin text-indigo-600" />
                  <span className="text-[10px] font-medium text-slate-500 italic">Consulting standards...</span>
                </div>
              </div>
            )}
          </div>

          {/* Footer */}
          <div className="p-4 bg-white border-t border-slate-100">
            <div className="flex gap-2">
              <input 
                type="text" 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                placeholder="Ask about your RCM analysis..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-xs focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim() || isLoading}
                className="p-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:opacity-50 transition-all shadow-md shadow-indigo-100"
              >
                <Send size={18} />
              </button>
            </div>
            <p className="text-[9px] text-slate-400 mt-2 text-center">Powered by Gemini 2.5 Flash Lite</p>
          </div>
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`w-14 h-14 rounded-full flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 ${isOpen ? 'bg-slate-800' : 'bg-indigo-600'}`}
      >
        {isOpen ? <X size={24} /> : <MessageSquare size={24} />}
        {!isOpen && (
          <div className="absolute top-0 right-0 w-4 h-4 bg-emerald-500 border-2 border-white rounded-full"></div>
        )}
      </button>
    </div>
  );
};

