  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);

  // Load studies from DB on mount and migrate old data if needed
  useEffect(() => {
    const initData = async () => {
      try {
        // 1. Check for legacy localStorage data
        const legacyData = localStorage.getItem('rcm_studies');
        if (legacyData) {
          try {
            const parsed = JSON.parse(legacyData) as SavedStudy[];
            if (Array.isArray(parsed) && parsed.length > 0) {
              console.log("Migrating legacy data to IndexedDB...");
              // Migrate each study to IndexedDB
              await Promise.all(parsed.map(study => saveStudyToDB(study)));
              // Clear legacy storage to avoid confusion
              localStorage.removeItem('rcm_studies');
            }
          } catch (e) {
            console.warn("Failed to parse legacy data", e);
          }
        }

        // 2. Load fresh data from IndexedDB
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };

    initData();
  }, []);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // Increased limit to 50MB since we now use IndexedDB
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }

    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type,
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setResults(null);

    try {
      const data = await generateRCMAnalysis(contextText, fileData);
      setResults(data);
    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Study Manager Actions
  const handleSaveStudy = async () => {
    if (!results && !contextText && !fileData) return;

    const nameToSave = studyName.trim() || "Untitled Analysis";
    const idToSave = currentStudyId || `study-${Date.now()}`;

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: Date.now(),
      items: results || [],
      contextText: contextText,
      fileName: fileData?.name
    };

    try {
      // Save to IndexedDB
      await saveStudyToDB(newStudy);

      // Update local state to reflect changes immediately
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);

      if (!currentStudyId) {
        setCurrentStudyId(idToSave);
      }

      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);
    } catch (e) {
      console.error("Save failed", e);
      setError("Failed to save study. Storage might be full.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);

      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null); // File data is heavy, usually handled separately or re-uploaded if needed for context

    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);

    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    setResults(newData);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">

      {/* Modals */}
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} />
      <OperationalContextBuilder 
        isOpen={showContextBuilder} 
        onClose={() => setShowContextBuilder(false)} 
        onComplete={(builtContext) => setContextText(builtContext)} 
      />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} />

      {/* AI Copilot - Minimal floating UI */}
      <AICopilot data={results} />

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`
        fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <Sidebar 
          studies={savedStudies}
          currentStudyId={currentStudyId}
          onSelect={handleLoadStudy}
          onDelete={handleDeleteStudy}
          onNew={handleNewStudy}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        {/* Header */}
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-16 px-4 flex items-center justify-between gap-4">

            <div className="flex items-center gap-3 min-w-0">
              <button 
                className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden"
                onClick={() => setIsSidebarOpen(true)}
              >
                <Menu size={24} />
              </button>

              <div className="hidden sm:flex p-1.5 bg-gradient-to-br from-indigo-600 to-indigo-700 rounded-lg text-white shadow-sm">
                <Cpu size={20} />
              </div>

              {/* Editable Title */}
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                    <input 
                      type="text" 
                      value={studyName}
                      onChange={(e) => setStudyName(e.target.value)}
                      placeholder="Untitled Analysis"
                      className="text-lg font-bold text-slate-800 bg-transparent border-b border-transparent hover:border-slate-300 focus:border-indigo-500 focus:outline-none transition-colors w-full sm:w-64 truncate"
                    />
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-medium uppercase tracking-wider">
                   {currentStudyId ? "Saved Study" : "Unsaved Draft"}
                 </p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              {/* Reference Guide Buttons */}
              <div className="hidden lg:flex items-center gap-1 border-r border-slate-200 pr-3 mr-1">
                <button
                  onClick={() => setShowSODReference(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                  title="FMECA Scoring Criteria"
                >
                  <BookOpen size={16} />
                  <span className="text-xs font-medium">S/O/D Guide</span>
                </button>
                <button
                  onClick={() => setShowDecisionLogic(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg transition-all"
                  title="Decision Logic Tree"
                >
                  <GitBranch size={16} />
                  <span className="text-xs font-medium">Logic Tree</span>
                </button>
              </div>

              {/* Save Status Indicator */}
              <div className="hidden sm:flex items-center text-xs font-medium transition-opacity duration-300">
                {justSaved ? (
                  <span className="text-emerald-600 flex items-center gap-1"><Check size={14} /> Saved</span>
                ) : (
                   <span className="text-slate-400">{results ? 'Unsaved changes' : ''}</span>
                )}
              </div>

              {/* Main Save Action */}
              <button
                onClick={handleSaveStudy}
                disabled={!results && !contextText}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all shadow-sm
                  ${justSaved 
                    ? 'bg-emerald-100 text-emerald-700 border border-emerald-200' 
                    : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
                  }
                  ${(!results && !contextText) ? 'opacity-50 cursor-not-allowed' : ''}
                `}
              >
                 {justSaved ? <Check size={18} /> : <Save size={18} />}
                 <span className="hidden sm:inline">{justSaved ? "Saved" : "Save"}</span>
              </button>

              <div className="h-6 w-px bg-slate-200 hidden sm:block"></div>

              <div className="hidden sm:flex items-center gap-2 text-xs text-slate-500 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-100">
                <span>Gemini 2.5</span>
                <Zap size={14} className="text-yellow-500 fill-yellow-500" />
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">

            {/* Intro Section - Only show when no results */}
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-bold text-slate-900 mb-3">Generate Maintenance Strategies</h2>
                <p className="text-slate-600 max-w-2xl text-lg leading-relaxed">
                  Start by giving your study a name above, then upload context documents or enter details to generate a comprehensive Reliability Centered Maintenance analysis.
                </p>
              </div>
            )}

            {/* Input Card */}
            <div className={`bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-200 bg-slate-50/80 px-6 pt-4 flex gap-6 overflow-x-auto">
                <button
                  onClick={() => setActiveTab('manual')}
                  className={`pb-4 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${
                    activeTab === 'manual' 
                      ? 'border-indigo-600 text-indigo-600' 
                      : 'border-transparent text-slate-500 hover:text-slate-700'
                  }`}
                >
                  <Type size={16} />
                  Manual Entry
                </button>
                <button
                  onClick={() => setActiveTab('upload')}
                  className={`pb-4 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${
                    activeTab === 'upload' 
                      ? 'border-indigo-600 text-indigo-600' 
                      : 'border-transparent text-slate-500 hover:text-slate-700'
                  }`}
                >
                  <Upload size={16} />
                  Document Upload
                </button>
              </div>

              <div className="p-6">
                {activeTab === 'manual' && (
                  <div className="space-y-4 animate-fade-in">
                    <div className="flex justify-between items-center">
                      <label className="block text-sm font-medium text-slate-700">
                        Operational Context Description
                      </label>
                      <button 
                        onClick={() => setShowContextBuilder(true)}
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-indigo-50 text-indigo-600 rounded-lg text-xs font-bold border border-indigo-100 hover:bg-indigo-100 transition-all shadow-sm"
                      >
                        <Sparkles size={14} className="fill-indigo-500" />
                        Context Builder Wizard
                      </button>
                    </div>
                    <textarea
                      className="w-full h-48 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-400"
                      placeholder="e.g., Centrifugal Pump P-101 is critical for cooling water circulation in Unit 2. It operates continuously at 3600 RPM. The fluid is river water containing some sediment..."
                      value={contextText}
                      onChange={(e) => setContextText(e.target.value)}
                    />
                  </div>
                )}

                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-300 rounded-xl p-8 flex flex-col items-center justify-center bg-slate-50 hover:bg-slate-100 transition-colors cursor-pointer relative group">
                        <input 
                          type="file" 
                          id="file-upload"
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                          accept=".txt,.pdf,.png,.jpg,.jpeg"
                          onChange={handleFileUpload}
                        />
                        {!fileData ? (
                          <>
                            <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                              <Upload size={24} />
                            </div>
                            <p className="text-sm font-medium text-slate-700">Click to upload or drag and drop</p>
                            <p className="text-xs text-slate-500 mt-1">PDF, TXT, or Images (Max 50MB)</p>
                          </>
                        ) : (
                          <div className="flex items-center gap-4 w-full max-w-md p-4 bg-white rounded-lg shadow-sm border border-slate-200 z-10">
                            <div className="p-3 bg-emerald-100 text-emerald-600 rounded-lg">
                              <FileCheck size={24} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium text-slate-900 truncate">{fileData.name}</p>
                              <p className="text-xs text-slate-500">{fileData.mimeType}</p>
                            </div>
                            <button 
                              onClick={(e) => {
                                e.preventDefault();
                                clearFile();
                              }}
                              className="p-2 text-slate-400 hover:text-red-500 transition-colors"
                            >
                              <Trash2 size={18} />
                            </button>
                          </div>
                        )}
                     </div>
                     {fileData && (
                       <div className="text-sm text-slate-500 flex items-center gap-2">
                          <Info size={14} />
                          Additional context can still be added in the manual tab.
                       </div>
                     )}
                  </div>
                )}

                {error && (
                  <div className="mt-4 p-4 bg-red-50 border border-red-100 rounded-xl text-red-600 text-sm flex items-center gap-2 animate-pulse">
                    <AlertTriangle size={16} />
                    {error}
                  </div>
                )}

                <div className="mt-6 flex justify-end">
                  <button
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className={`
                      flex items-center gap-2 px-6 py-3 rounded-xl text-sm font-semibold text-white shadow-lg shadow-indigo-200 transition-all
                      ${isLoading 
                        ? 'bg-indigo-400 cursor-not-allowed' 
                        : 'bg-indigo-600 hover:bg-indigo-700 hover:-translate-y-1'
                      }
                    `}
                  >
                    {isLoading ? (
                      <>
                        <Loader2 size={18} className="animate-spin" />
                        Analyzing...
                      </>
                    ) : (
                      <>
                        <Zap size={18} className="fill-indigo-200" />
                        Generate Analysis
                      </>
                    )}
                  </button>
                </div>
              </div>
            </div>

            {/* Results Section */}
            {results && (
              <AnalysisResult 
                data={results} 
                onUpdate={handleResultsUpdate}
              />
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { 
  MessageSquare, X, Send, Loader2, Bot, User, Sparkles, ChevronDown, 
  Wrench, Plus, Trash2, RefreshCw, Check, AlertCircle 
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposal?: ProposedAction;
}

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const parseAIResponse = (text: string): { cleanText: string, proposal?: ProposedAction } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/;
    const match = text.match(actionRegex);

    if (match) {
      try {
        const proposal = JSON.parse(match[1]);
        const cleanText = text.replace(actionRegex, '').trim();
        return { cleanText, proposal };
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }
    return { cleanText: text };
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const contextSummary = data ? data.map(i => ({
        id: i.id,
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        type: i.taskType,
        rpn: i.rpn
      })) : [];

      const prompt = `
        Current RCM Data: ${JSON.stringify(contextSummary)}
        User Input: ${userMsg}

        Instructions:
        1. If the user wants to change, add, or delete something, explain what you're doing and include an <ACTION> tag.
        2. Format: <ACTION>{"type": "ADD|UPDATE|DELETE", "reason": "why", "item": {...}}</ACTION>
        3. For ADD: Provide all required RCMItem fields (id will be generated).
        4. For UPDATE: Provide the "id" and only the fields that change.
        5. For DELETE: Provide the "id".
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          { role: 'user', parts: [{ text: prompt }] }
        ],
        config: {
          systemInstruction: "You are a Senior Reliability Engineer. You can help users build their RCM study. When requested to modify the data, provide your reasoning then output the structured JSON action within <ACTION> tags."
        }
      });

      const { cleanText, proposal } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "I've processed your request.", proposal }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Error: Failed to connect to the reliability expert." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applyAction = (proposal: ProposedAction) => {
    if (!data) return;

    let newData = [...data];

    if (proposal.type === 'ADD') {
      const newItem = {
        ...proposal.item,
        id: `rcm-ai-${Date.now()}`,
        rpn: (proposal.item.severity || 5) * (proposal.item.occurrence || 3) * (proposal.item.detection || 3)
      } as RCMItem;
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && proposal.item.id) {
      newData = newData.map(item => {
        if (item.id === proposal.item.id) {
          const updated = { ...item, ...proposal.item };
          updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item.id) {
      newData = newData.filter(item => item.id !== proposal.item.id);
    }

    onUpdate(newData);

    // Feedback in chat
    setMessages(prev => [...prev, { 
      role: 'model', 
      text: `✅ Successfully applied the ${proposal.type.toLowerCase()} operation to your analysis.` 
    }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[450px] h-[600px] bg-white rounded-2xl shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
          <div className="bg-indigo-600 p-4 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-white/20 rounded-lg"><Bot size={20} /></div>
              <div>
                <h3 className="font-bold text-sm">Reliability Co-pilot</h3>
                <div className="flex items-center gap-1.5">
                   <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse"></div>
                   <span className="text-[10px] text-indigo-100 font-medium">Interactive Mode Active</span>
                </div>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-colors"><ChevronDown size={20} /></button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center"><Sparkles size={24} /></div>
                <div>
                  <p className="text-sm font-bold text-slate-800">I can now modify your study!</p>
                  <p className="text-xs text-slate-500 mt-1 leading-relaxed">Try: "Add a fatigue failure for the main shaft" or "Change the detection score of the first item to 8"</p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-xs leading-relaxed shadow-sm ${
                  m.role === 'user' ? 'bg-indigo-600 text-white rounded-br-none' : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none'
                }`}>
                  {m.text}
                </div>

                {m.proposal && (
                  <div className="mt-2 w-[90%] bg-indigo-50 border border-indigo-100 rounded-xl p-3 shadow-sm animate-in zoom-in-95 duration-200">
                    <div className="flex items-center gap-2 mb-2">
                       {m.proposal.type === 'ADD' ? <Plus size={14} className="text-emerald-600" /> : 
                        m.proposal.type === 'UPDATE' ? <RefreshCw size={14} className="text-indigo-600" /> : 
                        <Trash2 size={14} className="text-red-600" />}
                       <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500">Proposed {m.proposal.type}</span>
                    </div>
                    <div className="text-[11px] text-slate-700 font-medium mb-3">
                      {m.proposal.reason}
                      {m.proposal.item.component && <div className="mt-1 text-indigo-600 font-bold">Target: {m.proposal.item.component}</div>}
                    </div>
                    <button 
                      onClick={() => applyAction(m.proposal!)}
                      className="w-full py-2 bg-indigo-600 text-white rounded-lg text-[10px] font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-1.5"
                    >
                      <Check size={12} /> Apply Changes to Analysis
                    </button>
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-2">
                  <Loader2 size={14} className="animate-spin text-indigo-600" />
                  <span className="text-[10px] font-medium text-slate-500 italic">Processing request...</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-white border-t border-slate-100">
            <div className="flex gap-2">
              <input 
                type="text" 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                placeholder="Tell me what to change..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-xs focus:ring-2 focus:ring-indigo-500 outline-none"
              />
              <button onClick={handleSend} disabled={!input.trim() || isLoading} className="p-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:opacity-50 transition-all">
                <Send size={18} />
              </button>
            </div>
          </div>
        </div>
      )}

      <button onClick={() => setIsOpen(!isOpen)} className={`w-14 h-14 rounded-full flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 ${isOpen ? 'bg-slate-800' : 'bg-indigo-600'}`}>
        {isOpen ? <X size={24} /> : <MessageSquare size={24} />}
        {!isOpen && <div className="absolute top-0 right-0 w-4 h-4 bg-emerald-500 border-2 border-white rounded-full"></div>}
      </button>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Info,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);

  // Load studies from DB on mount and migrate old data if needed
  useEffect(() => {
    const initData = async () => {
      try {
        const legacyData = localStorage.getItem('rcm_studies');
        if (legacyData) {
          try {
            const parsed = JSON.parse(legacyData) as SavedStudy[];
            if (Array.isArray(parsed) && parsed.length > 0) {
              await Promise.all(parsed.map(study => saveStudyToDB(study)));
              localStorage.removeItem('rcm_studies');
            }
          } catch (e) {
            console.warn("Failed to parse legacy data", e);
          }
        }
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type,
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setResults(null);

    try {
      const data = await generateRCMAnalysis(contextText, fileData);
      setResults(data);
    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Study Manager Actions
  const handleSaveStudy = async () => {
    if (!results && !contextText && !fileData) return;

    const nameToSave = studyName.trim() || "Untitled Analysis";
    const idToSave = currentStudyId || `study-${Date.now()}`;

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: Date.now(),
      items: results || [],
      contextText: contextText,
      fileName: fileData?.name
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentStudyId) {
        setCurrentStudyId(idToSave);
      }
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);
    } catch (e) {
      console.error("Save failed", e);
      setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    setResults(newData);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">

      {/* Modals */}
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} />
      <OperationalContextBuilder 
        isOpen={showContextBuilder} 
        onClose={() => setShowContextBuilder(false)} 
        onComplete={(builtContext) => setContextText(builtContext)} 
      />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} />

      {/* AI Copilot - Minimal floating UI */}
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`
        fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <Sidebar 
          studies={savedStudies}
          currentStudyId={currentStudyId}
          onSelect={handleLoadStudy}
          onDelete={handleDeleteStudy}
          onNew={handleNewStudy}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        {/* Header */}
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-16 px-4 flex items-center justify-between gap-4">

            <div className="flex items-center gap-3 min-w-0">
              <button 
                className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden"
                onClick={() => setIsSidebarOpen(true)}
              >
                <Menu size={24} />
              </button>

              <div className="hidden sm:flex p-1.5 bg-gradient-to-br from-indigo-600 to-indigo-700 rounded-lg text-white shadow-sm">
                <Cpu size={20} />
              </div>

              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                    <input 
                      type="text" 
                      value={studyName}
                      onChange={(e) => setStudyName(e.target.value)}
                      placeholder="Untitled Analysis"
                      className="text-lg font-bold text-slate-800 bg-transparent border-b border-transparent hover:border-slate-300 focus:border-indigo-500 focus:outline-none transition-colors w-full sm:w-64 truncate"
                    />
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-medium uppercase tracking-wider">
                   {currentStudyId ? "Saved Study" : "Unsaved Draft"}
                 </p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-1 border-r border-slate-200 pr-3 mr-1">
                <button
                  onClick={() => setShowSODReference(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                >
                  <BookOpen size={16} />
                  <span className="text-xs font-medium">S/O/D Guide</span>
                </button>
                <button
                  onClick={() => setShowDecisionLogic(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg transition-all"
                >
                  <GitBranch size={16} />
                  <span className="text-xs font-medium">Logic Tree</span>
                </button>
              </div>

              <div className="hidden sm:flex items-center text-xs font-medium transition-opacity duration-300">
                {justSaved ? (
                  <span className="text-emerald-600 flex items-center gap-1"><Check size={14} /> Saved</span>
                ) : (
                   <span className="text-slate-400">{results ? 'Unsaved changes' : ''}</span>
                )}
              </div>

              <button
                onClick={handleSaveStudy}
                disabled={!results && !contextText}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all shadow-sm
                  ${justSaved 
                    ? 'bg-emerald-100 text-emerald-700 border border-emerald-200' 
                    : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
                  }
                  ${(!results && !contextText) ? 'opacity-50 cursor-not-allowed' : ''}
                `}
              >
                 {justSaved ? <Check size={18} /> : <Save size={18} />}
                 <span className="hidden sm:inline">{justSaved ? "Saved" : "Save"}</span>
              </button>

              <div className="h-6 w-px bg-slate-200 hidden sm:block"></div>

              <div className="hidden sm:flex items-center gap-2 text-xs text-slate-500 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-100">
                <span>Gemini 2.5</span>
                <Zap size={14} className="text-yellow-500 fill-yellow-500" />
