                        ) : (
                          <div className="flex items-center gap-4 w-full max-w-md p-4 bg-white rounded-lg shadow-sm border border-slate-200 z-10">
                            <div className="p-3 bg-emerald-100 text-emerald-600 rounded-lg">
                              <FileCheck size={24} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium text-slate-900 truncate">{fileData.name}</p>
                            </div>
                            <button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-2 text-slate-400 hover:text-red-500">
                              <Trash2 size={18} />
                            </button>
                          </div>
                        )}
                     </div>
                  </div>
                )}

                {error && (
                  <div className="mt-4 p-4 bg-red-50 border border-red-100 rounded-xl text-red-600 text-sm flex items-center gap-2">
                    <AlertTriangle size={16} />
                    {error}
                  </div>
                )}

                <div className="mt-6 flex justify-end">
                  <button
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className={`flex items-center gap-2 px-6 py-3 rounded-xl text-sm font-semibold text-white shadow-lg ${isLoading ? 'bg-indigo-400' : 'bg-indigo-600 hover:bg-indigo-700'}`}
                  >
                    {isLoading ? <Loader2 size={18} className="animate-spin" /> : <Zap size={18} />}
                    {isLoading ? "Analyzing..." : "Generate Analysis"}
                  </button>
                </div>
              </div>
            </div>

            {results && (
              <AnalysisResult 
                data={results} 
                onUpdate={handleResultsUpdate}
              />
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

