/**
 * FormattedMessage component to handle technical text organization
 */
const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  // Simple formatting for bold and lists
  const lines = text.split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();

        // Handle basic bolding: **text**
        const formattedLine = line.split(/(\*\*.*?\*\*)/g).map((part, i) => {
          if (part.startsWith('**') && part.endsWith('**')) {
            return <strong key={i} className="font-bold">{part.slice(2, -2)}</strong>;
          }
          return part;
        });

        // Handle bullet points
        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className="shrink-0 mt-1.5 w-1 h-1 rounded-full bg-current opacity-60"></span>
              <span className="flex-1">{formattedLine.slice(1)}</span>
            </div>
          );
        }

        // Handle numbered lists
        if (/^\d+\.\s/.test(trimmed)) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className="shrink-0 font-bold opacity-60">{trimmed.split('.')[0]}.</span>
              <span className="flex-1">{formattedLine}</span>
            </div>
          );
        }

        // Empty line
        if (!trimmed) return <div key={idx} className="h-1"></div>;

        return <p key={idx} className="leading-relaxed">{formattedLine}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const parseAIResponse = (text: string): { cleanText: string, proposal?: ProposedAction } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/;
    const match = text.match(actionRegex);

    if (match) {
      try {
        const proposal = JSON.parse(match[1]);
        const cleanText = text.replace(actionRegex, '').trim();
        return { cleanText, proposal };
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }
    return { cleanText: text };
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const contextSummary = data ? data.map(i => ({
        id: i.id,
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        type: i.taskType,
        rpn: i.rpn
      })) : [];

      const prompt = `
        Current RCM Data: ${JSON.stringify(contextSummary)}
        User Input: ${userMsg}

        Instructions:
        1. If the user wants to change, add, or delete something, explain what you're doing and include an <ACTION> tag.
        2. Format: <ACTION>{"type": "ADD|UPDATE|DELETE", "reason": "why", "item": {...}}</ACTION>
        3. For ADD: Provide all required RCMItem fields (id will be generated). Mandatory: component, failureMode, maintenanceTask, taskType, consequenceCategory, iso14224Code.
        4. For UPDATE: Provide the "id" and only the fields that change.
        5. For DELETE: Provide the "id".
        6. Organize your response text using bullet points and paragraphs for maximum readability.
      `;

      const response = await ai.models.generateContent({
