                        <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={2} value={editForm.failureMode} onChange={(e) => handleChange('failureMode', e.target.value)} className="w-full px-2 py-1 border rounded" /><textarea rows={3} value={editForm.failureEffect} onChange={(e) => handleChange('failureEffect', e.target.value)} className="w-full px-2 py-1 border rounded" /></div></td>
                        <td className="px-2 py-4 align-top bg-white/50 border-l"><input type="number" min="1" max="10" value={editForm.severity} onChange={(e) => handleChange('severity', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.occurrence} onChange={(e) => handleChange('occurrence', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.detection} onChange={(e) => handleChange('detection', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-4 py-4 align-top text-center font-bold bg-white/50 border-r">{(editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1)}</td>
                        <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={3} value={editForm.maintenanceTask} onChange={(e) => handleChange('maintenanceTask', e.target.value)} className="w-full border rounded" /><input type="text" value={editForm.interval} onChange={(e) => handleChange('interval', e.target.value)} className="w-full border rounded" /></div></td>
                        <td className="px-6 py-4 align-top text-center text-slate-300"><File size={20} className="mx-auto" /></td>
                        <td className="px-6 py-4 align-top text-right"><div className="flex flex-col gap-2 items-end"><button onClick={handleSave} className="p-2 bg-emerald-500 text-white rounded"><Save size={16} /></button><button onClick={handleCancel} className="p-2 bg-slate-200 text-slate-600 rounded"><X size={16} /></button></div></td>
                      </tr>
                    );
                  }
                  const rpn = item.rpn || 0; const rpnStyle = getRPNColorStyle(rpn);
                  const consCat = item.consequenceCategory || '';
                  return (
                    <tr key={item.id} className={`group hover:bg-slate-50 ${isRegenerating ? 'opacity-60 bg-slate-50' : ''}`}>
                      <td className="px-6 py-4 font-medium align-top leading-tight text-xs">{item.component}</td>
                      <td className="px-6 py-4 align-top">
                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-full border ${consCat.includes('Hidden') ? 'bg-orange-50 text-orange-700 border-orange-200' : 'bg-blue-50 text-blue-700 border-blue-200'}`}>
                          {consCat}
                        </span>
                      </td>
                      <td className="px-6 py-4 align-top">
                        <span className="text-[10px] font-mono font-bold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded border border-indigo-100 uppercase">
                          {item.iso14224Code}
                        </span>
                      </td>
                      <td className="px-6 py-4 align-top"><div className="space-y-2"><div className="font-semibold text-[11px] border p-1 rounded inline-block bg-white shadow-sm leading-tight">{item.failureMode}</div><div className="text-slate-500 text-[10px] leading-relaxed line-clamp-2">{item.failureEffect}</div></div></td>
                      <td className="px-2 py-4 align-middle text-center border-l"><span className={getScoreColor(item.severity || 0)}>{item.severity || 0}</span></td>
                      <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.occurrence || 0)}>{item.occurrence || 0}</span></td>
                      <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.detection || 0)}>{item.detection || 0}</span></td>
                      <td className="px-4 py-4 align-middle border-r"><div className="flex flex-col gap-1"><span className={`text-xs font-bold ${rpnStyle.text}`}>{rpn}</span><div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full ${rpnStyle.bar}`} style={{width: `${Math.min((rpn/400)*100, 100)}%`}}></div></div></div></td>
                      <td className="px-6 py-4 align-top"><div className="font-medium text-xs leading-tight">{item.maintenanceTask}</div><div className="text-[10px] text-slate-400 font-mono mt-1">{item.interval}</div></td>
                      <td className="px-6 py-4 align-middle text-center">
                         {isRegenerating ? <RefreshCw size={20} className="animate-spin text-indigo-500 mx-auto" /> : item.inspectionSheet ? <button onClick={() => setViewSheet({ item })} className="text-emerald-500 hover:scale-110 transition-transform"><FileCheck size={22} /></button> : <button onClick={() => handleGenerateSingleSheet(item)} className="text-slate-300 hover:text-indigo-500"><File size={22} /></button>}
                      </td>
                      <td className="px-6 py-4 align-middle text-right opacity-0 group-hover:opacity-100 transition-opacity"><div className="flex justify-end gap-1"><button onClick={() => handleEdit(item)} className="p-1 text-slate-400 hover:text-indigo-600"><Pencil size={16} /></button><button onClick={() => handleDelete(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16} /></button></div></td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { 
  MessageSquare, X, Send, Loader2, Bot, User, Sparkles, ChevronDown, 
  Wrench, Plus, Trash2, RefreshCw, Check, AlertCircle 
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposal?: ProposedAction;
}

/**
 * FormattedMessage component to handle technical text organization
 */
const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = text.split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();

        // Helper to handle inline bolding
        const formatInline = (content: string) => {
          return content.split(/(\*\*.*?\*\*)/g).map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={idx + '-' + i} className="font-bold">{part.slice(2, -2)}</strong>;
            }
            return part;
          });
        };

        // Handle Headings (starting with ###)
        if (trimmed.startsWith('###')) {
          return (
            <div key={idx} className="mt-4 mb-1">
              <h4 className={`font-bold text-sm ${role === 'model' ? 'text-indigo-700' : 'text-white underline'}`}>
                {formatInline(trimmed.replace(/^###\s*/, ''))}
              </h4>
            </div>
          );
        }

        // Handle bullet points
        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          const content = trimmed.replace(/^[*|-]\s*/, '');
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 mt-1.5 w-1 h-1 rounded-full bg-current ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}></span>
              <span className="flex-1">{formatInline(content)}</span>
            </div>
          );
        }

        // Handle numbered lists
        const numMatch = trimmed.match(/^(\d+)\.\s(.*)/);
        if (numMatch) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 font-bold text-[10px] mt-0.5 ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}>
                {numMatch[1]}.
              </span>
              <span className="flex-1">{formatInline(numMatch[2])}</span>
            </div>
          );
        }

        // Handle empty lines as spacers
        if (!trimmed) return <div key={idx} className="h-1"></div>;

        // Normal paragraph
        return <p key={idx} className="leading-relaxed">{formatInline(line)}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const parseAIResponse = (text: string): { cleanText: string, proposal?: ProposedAction } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/;
    const match = text.match(actionRegex);

    if (match) {
      try {
        const proposal = JSON.parse(match[1]);
        const cleanText = text.replace(actionRegex, '').trim();
        return { cleanText, proposal };
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }
    return { cleanText: text };
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => item !== null && item !== undefined);
      const contextSummary = safeData.map(i => ({
        id: i.id,
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        type: i.taskType,
        rpn: i.rpn
      }));

      const prompt = `
        Current RCM Data: ${JSON.stringify(contextSummary)}
        User Input: ${userMsg}

        Instructions:
        1. If the user wants to change, add, or delete something, explain what you're doing and include an <ACTION> tag.
        2. Format: <ACTION>{"type": "ADD|UPDATE|DELETE", "reason": "why", "item": {...}}</ACTION>
        3. For ADD: Provide all required RCMItem fields (id will be generated). Mandatory: component, failureMode, maintenanceTask, taskType, consequenceCategory, iso14224Code.
        4. For UPDATE: Provide the "id" and only the fields that change.
        5. For DELETE: Provide the "id".
        6. Organize your response text using clear sections. Use "### Section Name" for headings. Use bullet points for lists. Be concise.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          { role: 'user', parts: [{ text: prompt }] }
        ],
        config: {
          systemInstruction: "You are a Senior Reliability Engineer. You can help users build their RCM study. When requested to modify the data, provide your reasoning then output the structured JSON action within <ACTION> tags. Structure your advice using '### Heading' for sections, bold text for emphasis, and bullet points for technical details."
        }
      });

      const { cleanText, proposal } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "I've processed your request.", proposal }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Error: Failed to connect to the reliability expert." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applyAction = (proposal: ProposedAction) => {
    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}`,
        component: proposal.item?.component || 'New Component',
        function: proposal.item?.function || 'Component Function',
        functionalFailure: proposal.item?.functionalFailure || 'Functional Failure',
        failureMode: proposal.item?.failureMode || 'Failure Mechanism',
        failureEffect: proposal.item?.failureEffect || 'Effect on system',
        consequenceCategory: proposal.item?.consequenceCategory || 'Evident - Operational',
        iso14224Code: proposal.item?.iso14224Code || 'Wear',
        criticality: proposal.item?.criticality || 'Medium',
        severity: proposal.item?.severity || 5,
        occurrence: proposal.item?.occurrence || 3,
        detection: proposal.item?.detection || 3,
        rpn: (proposal.item?.severity || 5) * (proposal.item?.occurrence || 3) * (proposal.item?.detection || 3),
        maintenanceTask: proposal.item?.maintenanceTask || 'Inspection',
        interval: proposal.item?.interval || 'Monthly',
        taskType: (proposal.item?.taskType as any) || 'Condition Monitoring',
        ...proposal.item,
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && proposal.item?.id) {
      newData = newData.map(item => {
        if (item && item.id === proposal.item.id) {
          const updated = { ...item, ...proposal.item };
          updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item?.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    setMessages(prev => [...prev, { 
      role: 'model', 
      text: `### Action Complete\n✅ **Success:** Applied the **${proposal.type.toLowerCase()}** operation. Your changes have been merged into the analysis table.` 
    }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[450px] h-[600px] bg-white rounded-2xl shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
          <div className="bg-indigo-600 p-4 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-white/20 rounded-lg"><Bot size={20} /></div>
              <div>
                <h3 className="font-bold text-sm">Reliability Co-pilot</h3>
                <div className="flex items-center gap-1.5">
                   <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse"></div>
                   <span className="text-[10px] text-indigo-100 font-medium">Interactive Mode Active</span>
                </div>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-colors"><ChevronDown size={20} /></button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center"><Sparkles size={24} /></div>
                <div>
                  <p className="text-sm font-bold text-slate-800">I can now modify your study!</p>
                  <p className="text-xs text-slate-500 mt-1 leading-relaxed">Try: "Add a fatigue failure for the main shaft" or "Change the detection score of the first item to 8"</p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`max-w-[90%] p-4 rounded-2xl text-[13px] shadow-sm ${
                  m.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-br-none' 
                    : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>

                {m.proposal && (
                  <div className="mt-2 w-[90%] bg-white border border-indigo-100 rounded-xl p-4 shadow-md animate-in zoom-in-95 duration-200 border-l-4 border-l-indigo-500">
                    <div className="flex items-center gap-2 mb-3">
                       <div className={`p-1.5 rounded-lg ${
                         m.proposal.type === 'ADD' ? 'bg-emerald-50 text-emerald-600' : 
                         m.proposal.type === 'UPDATE' ? 'bg-indigo-50 text-indigo-600' : 
                         'bg-red-50 text-red-600'
                       }`}>
                         {m.proposal.type === 'ADD' ? <Plus size={14} /> : 
                          m.proposal.type === 'UPDATE' ? <RefreshCw size={14} /> : 
                          <Trash2 size={14} />}
                       </div>
                       <span className="text-[11px] font-bold uppercase tracking-wider text-slate-500">Suggested Action: {m.proposal.type}</span>
                    </div>
                    <div className="text-[12px] text-slate-700 font-medium mb-4 leading-relaxed">
                      {m.proposal.reason}
                      {m.proposal.item?.component && (
                        <div className="mt-2 p-2 bg-slate-50 rounded-lg border border-slate-100">
                          <span className="text-[10px] text-slate-400 font-bold uppercase block mb-0.5">Target Component</span>
                          <span className="text-indigo-600 font-bold">{m.proposal.item.component}</span>
                        </div>
                      )}
                    </div>
                    <button 
                      onClick={() => applyAction(m.proposal!)}
                      className="w-full py-2.5 bg-indigo-600 text-white rounded-xl text-[12px] font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-100"
                    >
                      <Check size={14} /> Confirm and Apply
                    </button>
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-2">
                  <Loader2 size={14} className="animate-spin text-indigo-600" />
                  <span className="text-[11px] font-medium text-slate-500 italic">Expert is thinking...</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-white border-t border-slate-100">
            <div className="flex gap-2">
              <input 
                type="text" 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                placeholder="Suggest a change to the analysis..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-[13px] focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              />
              <button onClick={handleSend} disabled={!input.trim() || isLoading} className="p-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:opacity-50 transition-all shadow-md shadow-indigo-100">
                <Send size={20} />
              </button>
            </div>
          </div>
        </div>
      )}

      <button onClick={() => setIsOpen(!isOpen)} className={`w-14 h-14 rounded-full flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 ${isOpen ? 'bg-slate-800' : 'bg-indigo-600'}`}>
        {isOpen ? <X size={24} /> : <MessageSquare size={24} />}
        {!isOpen && <div className="absolute top-0 right-0 w-4 h-4 bg-emerald-500 border-2 border-white rounded-full"></div>}
      </button>
