import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { 
  MessageSquare, X, Send, Loader2, Bot, Sparkles, ChevronDown, 
  Plus, Trash2, RefreshCw, Check
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposal?: ProposedAction;
}

/**
 * FormattedMessage component to handle technical text organization
 */
const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = text.split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();

        const formatInline = (content: string) => {
          return content.split(/(\*\*.*?\*\*)/g).map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={idx + '-' + i} className="font-bold">{part.slice(2, -2)}</strong>;
            }
            return part;
          });
        };

        if (trimmed.startsWith('###')) {
          return (
            <div key={idx} className="mt-4 mb-1">
              <h4 className={`font-bold text-sm ${role === 'model' ? 'text-indigo-700' : 'text-white underline'}`}>
                {formatInline(trimmed.replace(/^###\s*/, ''))}
              </h4>
            </div>
          );
        }

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          const content = trimmed.replace(/^[*|-]\s*/, '');
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 mt-1.5 w-1 h-1 rounded-full bg-current ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}></span>
              <span className="flex-1">{formatInline(content)}</span>
            </div>
          );
        }

        const numMatch = trimmed.match(/^(\d+)\.\s(.*)/);
        if (numMatch) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 font-bold text-[10px] mt-0.5 ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}>
                {numMatch[1]}.
              </span>
              <span className="flex-1">{formatInline(numMatch[2])}</span>
            </div>
          );
        }

        if (!trimmed) return <div key={idx} className="h-1"></div>;

        return <p key={idx} className="leading-relaxed">{formatInline(line)}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const lastScrollTop = useRef<number>(0);

  // Auto-scroll chat to bottom when new messages arrive
  useEffect(() => {
    if (isOpen && scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  // Remember internal scroll position when opening/closing
  const handleToggle = (e: React.MouseEvent) => {
    e.preventDefault(); // Prevent default anchor/button behavior that might trigger scroll
    if (isOpen && scrollRef.current) {
      lastScrollTop.current = scrollRef.current.scrollTop;
    }
    setIsOpen(!isOpen);
  };

  // Restore scroll position after animation/render
  useEffect(() => {
    if (isOpen && scrollRef.current && lastScrollTop.current > 0) {
      scrollRef.current.scrollTop = lastScrollTop.current;
    }
  }, [isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposal?: ProposedAction } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/;
    const match = text.match(actionRegex);

    if (match) {
      try {
        const proposal = JSON.parse(match[1]);
        const cleanText = text.replace(actionRegex, '').trim();
        return { cleanText, proposal };
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }
    return { cleanText: text };
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => item !== null && item !== undefined);
      const contextSummary = safeData.map(i => ({
        id: i.id,
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        type: i.taskType,
        rpn: i.rpn
      }));

      const prompt = `
        Current RCM Data: ${JSON.stringify(contextSummary)}
        User Input: ${userMsg}

        Actionable Change Instructions:
        1. If the user wants to change, add, or delete something, include an <ACTION> tag.
        2. Format: <ACTION>{"type": "ADD|UPDATE|DELETE", "reason": "why", "item": {...}}</ACTION>
        3. For ADD: You MUST provide ALL RCMItem fields. 
           - failureMode: formatted strictly as '[Mechanism] due to [Cause]'.
           - taskType: must be one of [Condition Monitoring, Time-Based, Run-to-Failure, Redesign, Failure Finding, Lubrication, Servicing, Restoration, Replacement].
           - consequenceCategory: must be one of [Hidden - Safety/Env, Hidden - Operational, Evident - Safety/Env, Evident - Operational, Evident - Non-Operational].
           - iso14224Code: specific failure mechanism (Wear, Corrosion, etc).
        4. Organize your expert explanation using "### Section Name" headings.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          { role: 'user', parts: [{ text: prompt }] }
        ],
        config: {
          systemInstruction: "You are a Senior Reliability Engineer. You act with the same logic and standards as the primary analysis service. You use SAE JA1011 RCM principles and ISO 14224 taxonomy. You provide professional, technically accurate advice. You never hallucinate components. You balance predictive and proactive tasks based on physics-of-failure."
        }
      });

      const { cleanText, proposal } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "I've processed your request.", proposal }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Error: Failed to connect to the reliability expert." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applyAction = (proposal: ProposedAction) => {
    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}`,
        component: proposal.item?.component || 'New Component',
        function: proposal.item?.function || 'Component Function',
        functionalFailure: proposal.item?.functionalFailure || 'Functional Failure',
        failureMode: proposal.item?.failureMode || 'Failure Mechanism',
        failureEffect: proposal.item?.failureEffect || 'Effect on system',
        consequenceCategory: proposal.item?.consequenceCategory || 'Evident - Operational',
        iso14224Code: proposal.item?.iso14224Code || 'Wear',
        criticality: proposal.item?.criticality || 'Medium',
        severity: proposal.item?.severity || 5,
        occurrence: proposal.item?.occurrence || 3,
        detection: proposal.item?.detection || 3,
        rpn: (proposal.item?.severity || 5) * (proposal.item?.occurrence || 3) * (proposal.item?.detection || 3),
        maintenanceTask: proposal.item?.maintenanceTask || 'Inspection',
        interval: proposal.item?.interval || 'Monthly',
        taskType: (proposal.item?.taskType as any) || 'Condition Monitoring',
        ...proposal.item,
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && proposal.item?.id) {
      newData = newData.map(item => {
        if (item && item.id === proposal.item.id) {
          const updated = { ...item, ...proposal.item };
          updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item?.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    setMessages(prev => [...prev, { 
      role: 'model', 
      text: `### Action Complete\n✅ **Success:** Applied the **${proposal.type.toLowerCase()}** operation. The updated analysis follows standard SAE JA1011/ISO 14224 logic.` 
    }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[450px] h-[600px] bg-white rounded-2xl shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
          <div className="bg-indigo-600 p-4 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-white/20 rounded-lg"><Bot size={20} /></div>
              <div>
                <h3 className="font-bold text-sm">Reliability Co-pilot</h3>
                <div className="flex items-center gap-1.5">
                   <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse"></div>
                   <span className="text-[10px] text-indigo-100 font-medium">Interactive Mode Active</span>
                </div>
              </div>
            </div>
            <button 
              type="button"
              onClick={handleToggle} 
              className="hover:bg-white/10 p-2 rounded-full transition-colors"
            >
              <ChevronDown size={20} />
            </button>
          </div>

          <div 
            ref={scrollRef} 
            className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 custom-scrollbar"
          >
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center"><Sparkles size={24} /></div>
                <div>
                  <p className="text-sm font-bold text-slate-800">Ready to optimize your study!</p>
                  <p className="text-xs text-slate-500 mt-1 leading-relaxed">Ask me to add failures, change risk scores, or explain the logic behind specific tasks.</p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`max-w-[90%] p-4 rounded-2xl text-[13px] shadow-sm ${
                  m.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-br-none' 
                    : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>

                {m.proposal && (
                  <div className="mt-2 w-[90%] bg-white border border-indigo-100 rounded-xl p-4 shadow-md animate-in zoom-in-95 duration-200 border-l-4 border-l-indigo-500">
                    <div className="flex items-center gap-2 mb-3">
                       <div className={`p-1.5 rounded-lg ${
                         m.proposal.type === 'ADD' ? 'bg-emerald-50 text-emerald-600' : 
                         m.proposal.type === 'UPDATE' ? 'bg-indigo-50 text-indigo-600' : 
                         'bg-red-50 text-red-600'
                       }`}>
                         {m.proposal.type === 'ADD' ? <Plus size={14} /> : 
                          m.proposal.type === 'UPDATE' ? <RefreshCw size={14} /> : 
                          <Trash2 size={14} />}
                       </div>
                       <span className="text-[11px] font-bold uppercase tracking-wider text-slate-500">Suggested Action: {m.proposal.type}</span>
                    </div>
                    <div className="text-[12px] text-slate-700 font-medium mb-4 leading-relaxed">
                      {m.proposal.reason}
                      {m.proposal.item?.component && (
                        <div className="mt-2 p-2 bg-slate-50 rounded-lg border border-slate-100">
                          <span className="text-[10px] text-slate-400 font-bold uppercase block mb-0.5">Target Component</span>
                          <span className="text-indigo-600 font-bold">{m.proposal.item.component}</span>
                        </div>
                      )}
                    </div>
                    <button 
                      type="button"
                      onClick={() => applyAction(m.proposal!)}
                      className="w-full py-2.5 bg-indigo-600 text-white rounded-xl text-[12px] font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-100"
                    >
                      <Check size={14} /> Confirm and Apply
                    </button>
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-2">
                  <Loader2 size={14} className="animate-spin text-indigo-600" />
