          <div className="p-4 bg-white border-t border-slate-100">
            <div className="flex gap-2">
              <input 
                type="text" 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                placeholder="Suggest a change to the analysis..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-[13px] focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              />
