  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[450px] h-[600px] bg-white rounded-2xl shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
          <div className="bg-indigo-600 p-4 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-white/20 rounded-lg shadow-inner"><Bot size={20} /></div>
              <div>
                <h3 className="font-bold text-sm tracking-tight">Reliability Co-pilot</h3>
                <div className="flex items-center gap-1.5">
                   <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse"></div>
                   <span className="text-[10px] text-indigo-100 font-bold uppercase tracking-wider opacity-80">Expert Mode</span>
                </div>
              </div>
            </div>
            <button 
              onClick={() => setIsOpen(false)} 
              className="hover:bg-white/10 p-2 rounded-full transition-colors"
            >
              <ChevronDown size={22} />
            </button>
          </div>

          <div 
            ref={scrollRef} 
            onScroll={handleScroll}
            className="flex-1 overflow-y-auto p-4 space-y-5 bg-slate-50 custom-scrollbar"
          >
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
                <div className="w-14 h-14 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center shadow-sm"><Sparkles size={28} /></div>
                <div>
                  <p className="text-sm font-bold text-slate-800">Advanced Reliability Expert</p>
                  <p className="text-xs text-slate-500 mt-1 leading-relaxed px-4">
                    I can refine failure modes, adjust RPN scores, or propose new maintenance tasks based on your operational context.
                  </p>
                </div>
