            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[92%] p-4 rounded-2xl text-[13px] shadow-sm ${
                  m.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-br-none' 
                    : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>

                {m.proposal && renderProposal(m.proposal)}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-3">
                  <div className="flex gap-1">
                    <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce"></div>
                  </div>
                  <span className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">Processing</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-white border-t border-slate-100">
            <div className="flex gap-2">
              <input 
                type="text" 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                placeholder="Ask for an update or new analysis..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-3.5 text-[13px] focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder:text-slate-400"
              />
              <button 
                onClick={handleSend} 
                disabled={!input.trim() || isLoading} 
                className="p-3.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 active:scale-95 disabled:opacity-50 transition-all shadow-md shadow-indigo-100"
              >
                <Send size={20} />
              </button>
            </div>
          </div>
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)} 
        className={`w-14 h-14 rounded-full flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 ${isOpen ? 'bg-slate-800' : 'bg-indigo-600'}`}
      >
        {isOpen ? <X size={24} /> : <MessageSquare size={24} />}
        {!isOpen && <div className="absolute top-0 right-0 w-4 h-4 bg-emerald-500 border-2 border-white rounded-full"></div>}
      </button>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { 
  MessageSquare, X, Send, Loader2, Bot, Sparkles, ChevronDown, 
  Plus, Trash2, RefreshCw, Check, Info, ListChecks, CheckCircle2
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; // Internal ID for tracking in the UI
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
}

/**
 * FormattedMessage component to handle technical text organization
 */
const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = text.split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();

        const formatInline = (content: string) => {
          return content.split(/(\*\*.*?\*\*)/g).map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={idx + '-' + i} className="font-bold">{part.slice(2, -2)}</strong>;
            }
            return part;
          });
        };

        if (trimmed.startsWith('###')) {
          return (
            <div key={idx} className="mt-4 mb-1">
              <h4 className={`font-bold text-sm ${role === 'model' ? 'text-indigo-700' : 'text-white underline'}`}>
                {formatInline(trimmed.replace(/^###\s*/, ''))}
              </h4>
            </div>
          );
        }

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          const content = trimmed.replace(/^[*|-]\s*/, '');
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 mt-1.5 w-1 h-1 rounded-full bg-current ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}></span>
              <span className="flex-1">{formatInline(content)}</span>
            </div>
          );
        }

        const numMatch = trimmed.match(/^(\d+)\.\s(.*)/);
        if (numMatch) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 font-bold text-[10px] mt-0.5 ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}>
                {numMatch[1]}.
              </span>
              <span className="flex-1">{formatInline(numMatch[2])}</span>
            </div>
          );
        }

        if (!trimmed) return <div key={idx} className="h-1"></div>;

        return <p key={idx} className="leading-relaxed">{formatInline(line)}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const chatScrollPos = useRef<number>(0);

  // Persistence for scroll position
  useEffect(() => {
    if (isOpen && scrollRef.current) {
      if (chatScrollPos.current > 0) {
        scrollRef.current.scrollTop = chatScrollPos.current;
      } else {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [isOpen]);

  const handleScroll = () => {
    if (scrollRef.current) {
      chatScrollPos.current = scrollRef.current.scrollTop;
    }
  };

  useEffect(() => {
    if (isOpen && scrollRef.current && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.role === 'user') {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages, isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          proposals.push({
            ...a,
            id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
            applied: false
          });
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => item !== null && item !== undefined);

      const contextSummary = safeData.slice(-10).map(i => ({
        id: i.id,
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        type: i.taskType,
        rpn: i.rpn
      }));

      const prompt = `
        Current RCM Data Context (Last 10 items): ${JSON.stringify(contextSummary)}
        User Instruction: ${userMsg}

        Engineering Guidelines:
        1. If the user asks for a new component or section (e.g. 'Add a diverter'), identify ALL critical failure modes for it (usually 3-5 items).
        2. Format failure modes strictly as '[Mechanism] due to [Cause]'.
        3. Assign realistic S, O, D scores (1-10) and ISO 14224 codes.
        4. Propose actionable, professional maintenance tasks (Vibration, Thermography, Oil, etc).
        5. You MUST include one or more <ACTION> tags for the proposed changes.
        6. Format for one or multiple changes: <ACTION>[{"type": "ADD|UPDATE|DELETE", "reason": "Why...", "item": {...}}]</ACTION>
        7. For ADD: Provide ALL RCMItem fields except 'id' and 'rpn'.
        8. Structure your text explanation with '### Section' headings.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are a World-Class Reliability Lead. Your logic mirrors SAE JA1011 standards. You provide deep technical analysis, not placeholders. When adding components, analyze their sub-systems (bearings, seals, electrical, structures) and propose appropriate predictive or proactive tasks."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Analysis integrated.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Expert consultation unavailable. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  }

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item?.component || 'New Component',
        function: proposal.item?.function || 'Perform intended work',
        functionalFailure: proposal.item?.functionalFailure || 'Total loss of function',
        failureMode: proposal.item?.failureMode || 'Wear due to usage',
        failureEffect: proposal.item?.failureEffect || 'System downtime',
        consequenceCategory: proposal.item?.consequenceCategory || 'Evident - Operational',
        iso14224Code: proposal.item?.iso14224Code || 'Wear',
        criticality: proposal.item?.criticality || 'Medium',
        severity: proposal.item?.severity || 5,
        occurrence: proposal.item?.occurrence || 3,
        detection: proposal.item?.detection || 3,
        rpn: (proposal.item?.severity || 5) * (proposal.item?.occurrence || 3) * (proposal.item?.detection || 3),
        maintenanceTask: proposal.item?.maintenanceTask || 'Inspection',
        interval: proposal.item?.interval || 'Monthly',
        taskType: (proposal.item?.taskType as any) || 'Condition Monitoring',
        ...proposal.item,
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && proposal.item?.id) {
      newData = newData.map(item => {
        if (item && item.id === proposal.item.id) {
          const updated = { ...item, ...proposal.item };
          updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item?.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    // Update the message state to show this specific item as applied
    const newMessages = [...messages];
    newMessages[messageIndex].proposals = message.proposals.map(p => 
      p.id === proposalId ? { ...p, applied: true } : p
    );
    setMessages(newMessages);
  };

  const applyAllActions = (messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const unapplied = message.proposals.filter(p => !p.applied);
    if (unapplied.length === 0) return;

    let newData = data ? [...data] : [];

    unapplied.forEach(proposal => {
      if (proposal.type === 'ADD') {
        const newItem: RCMItem = {
          id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          component: proposal.item?.component || 'New Component',
          function: proposal.item?.function || 'Perform intended work',
          functionalFailure: proposal.item?.functionalFailure || 'Total loss of function',
          failureMode: proposal.item?.failureMode || 'Wear due to usage',
          failureEffect: proposal.item?.failureEffect || 'System downtime',
          consequenceCategory: proposal.item?.consequenceCategory || 'Evident - Operational',
          iso14224Code: proposal.item?.iso14224Code || 'Wear',
          criticality: proposal.item?.criticality || 'Medium',
          severity: proposal.item?.severity || 5,
          occurrence: proposal.item?.occurrence || 3,
          detection: proposal.item?.detection || 3,
          rpn: (proposal.item?.severity || 5) * (proposal.item?.occurrence || 3) * (proposal.item?.detection || 3),
          maintenanceTask: proposal.item?.maintenanceTask || 'Inspection',
          interval: proposal.item?.interval || 'Monthly',
          taskType: (proposal.item?.taskType as any) || 'Condition Monitoring',
          ...proposal.item,
        };
        newData.push(newItem);
      } 
      else if (proposal.type === 'UPDATE' && proposal.item?.id) {
        newData = newData.map(item => {
          if (item && item.id === proposal.item.id) {
            const updated = { ...item, ...proposal.item };
            updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
            return updated;
          }
          return item;
        });
      } 
      else if (proposal.type === 'DELETE' && proposal.item?.id) {
        newData = newData.filter(item => item && item.id !== proposal.item.id);
      }
    });

    onUpdate(newData);

    const newMessages = [...messages];
    newMessages[messageIndex].proposals = message.proposals.map(p => ({ ...p, applied: true }));
    setMessages(newMessages);
  };

  const renderProposalsSection = (message: Message, messageIndex: number) => {
    if (!message.proposals || message.proposals.length === 0) return null;

    const unappliedCount = message.proposals.filter(p => !p.applied).length;

    return (
      <div className="mt-4 w-full space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="flex items-center justify-between px-2 mb-2">
          <h5 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <ListChecks size={14} /> Proposed Draft Changes ({message.proposals.length})
          </h5>
          {unappliedCount > 1 && (
            <button 
              onClick={() => applyAllActions(messageIndex)}
              className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-1 rounded hover:bg-indigo-100 transition-colors flex items-center gap-1 border border-indigo-100"
            >
              <CheckCircle2 size={12} /> Implement All
            </button>
          )}
        </div>

        {message.proposals.map((p) => (
          <div 
            key={p.id} 
            className={`bg-white border rounded-2xl p-4 shadow-sm transition-all border-l-4 ${
              p.applied ? 'border-emerald-500 bg-emerald-50/20' : 
              p.type === 'ADD' ? 'border-indigo-500' : 
              p.type === 'UPDATE' ? 'border-amber-500' : 'border-red-500'
            }`}
          >
            <div className="flex justify-between items-start gap-3 mb-2">
               <div>
                  <div className="flex items-center gap-2 mb-1">
                    <span className={`text-[10px] font-bold uppercase tracking-tighter px-1.5 py-0.5 rounded ${
                      p.applied ? 'bg-emerald-500 text-white' : 
                      p.type === 'ADD' ? 'bg-indigo-600 text-white' : 
                      p.type === 'UPDATE' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                    }`}>
                      {p.applied ? 'Active' : p.type}
                    </span>
                    <span className="text-[12px] font-bold text-slate-800 truncate">{p.item.component || 'Asset Component'}</span>
                  </div>
                  <p className="text-[11px] text-slate-500 italic leading-snug">"{p.reason}"</p>
               </div>

               {!p.applied ? (
                 <button 
                   onClick={() => applySingleAction(p.id, messageIndex)}
                   className="p-2 bg-slate-900 text-white rounded-xl hover:bg-indigo-600 transition-all shrink-0 shadow-lg shadow-slate-200"
                   title="Apply change"
                 >
                   <Plus size={16} />
                 </button>
               ) : (
                 <div className="p-2 bg-emerald-100 text-emerald-600 rounded-xl shrink-0">
                    <Check size={16} />
                 </div>
               )}
            </div>

            {!p.applied && p.item.failureMode && (
              <div className="text-[11px] font-medium text-slate-700 bg-slate-50 border border-slate-100 rounded-lg p-2.5 mt-2 leading-relaxed">
                <span className="text-[9px] font-bold text-slate-400 block mb-0.5">FAILURE MODE:</span>
                {p.item.failureMode}
              </div>
            )}
          </div>
        ))}
      </div>
    );
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[480px] h-[650px] bg-white rounded-3xl shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
          <div className="bg-indigo-600 p-5 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-white/20 rounded-xl shadow-inner"><Bot size={22} /></div>
              <div>
                <h3 className="font-bold text-base tracking-tight leading-none">Reliability Lead</h3>
                <div className="flex items-center gap-1.5 mt-1.5">
                   <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse"></div>
                   <span className="text-[10px] text-indigo-100 font-bold uppercase tracking-widest opacity-80">SAE JA1011 Compliant</span>
                </div>
              </div>
            </div>
            <button 
              onClick={() => setIsOpen(false)} 
              className="hover:bg-white/10 p-2 rounded-full transition-colors"
            >
              <ChevronDown size={24} />
            </button>
          </div>

          <div 
            ref={scrollRef} 
            onScroll={handleScroll}
            className="flex-1 overflow-y-auto p-5 space-y-6 bg-slate-50 custom-scrollbar"
          >
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-6">
                <div className="w-16 h-16 bg-indigo-100 text-indigo-600 rounded-3xl flex items-center justify-center shadow-sm rotate-3"><Sparkles size={32} /></div>
                <div className="space-y-2">
                  <p className="text-base font-extrabold text-slate-800">Operational Improvement Mode</p>
                  <p className="text-xs text-slate-500 leading-relaxed px-6">
                    I can generate specific mini-studies for new components, refine your existing RPN scores, or propose better maintenance tasks.
                  </p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`max-w-[95%] p-4 rounded-2xl text-[13px] shadow-sm ${
                  m.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-br-none' 
                    : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>

                {renderProposalsSection(m, i)}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 p-4 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-4">
                  <div className="flex gap-1">
                    <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce"></div>
                  </div>
                  <span className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">Engineering Analysis</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-5 bg-white border-t border-slate-100">
            <div className="flex gap-3">
              <input 
                type="text" 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                placeholder="Describe a new component or failure..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-[13px] focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder:text-slate-400 font-medium"
              />
              <button 
                onClick={handleSend} 
                disabled={!input.trim() || isLoading} 
                className="p-4 bg-indigo-600 text-white rounded-2xl hover:bg-indigo-700 active:scale-95 disabled:opacity-50 transition-all shadow-xl shadow-indigo-100"
              >
                <Send size={22} />
              </button>
            </div>
          </div>
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)} 
        className={`w-14 h-14 rounded-full flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 ${isOpen ? 'bg-slate-800' : 'bg-indigo-600'}`}
      >
        {isOpen ? <X size={24} /> : <MessageSquare size={24} />}
        {!isOpen && <div className="absolute top-0 right-0 w-4 h-4 bg-emerald-500 border-2 border-white rounded-full"></div>}
      </button>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { 
  MessageSquare, X, Send, Loader2, Bot, Sparkles, ChevronDown, 
  Plus, Trash2, RefreshCw, Check, Info, ListChecks, CheckCircle2,
  AlertTriangle, Wrench
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; // Internal ID for tracking in the UI
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
}

/**
 * FormattedMessage component to handle technical text organization
 */
const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = text.split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();

        const formatInline = (content: string) => {
          return content.split(/(\*\*.*?\*\*)/g).map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={idx + '-' + i} className="font-bold">{part.slice(2, -2)}</strong>;
            }
            return part;
          });
        };

        if (trimmed.startsWith('###')) {
          return (
            <div key={idx} className="mt-4 mb-1">
              <h4 className={`font-bold text-sm ${role === 'model' ? 'text-indigo-700' : 'text-white underline'}`}>
                {formatInline(trimmed.replace(/^###\s*/, ''))}
              </h4>
            </div>
          );
        }

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          const content = trimmed.replace(/^[*|-]\s*/, '');
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 mt-1.5 w-1 h-1 rounded-full bg-current ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}></span>
              <span className="flex-1">{formatInline(content)}</span>
            </div>
          );
        }

        const numMatch = trimmed.match(/^(\d+)\.\s(.*)/);
        if (numMatch) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 font-bold text-[10px] mt-0.5 ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}>
                {numMatch[1]}.
              </span>
              <span className="flex-1">{formatInline(numMatch[2])}</span>
            </div>
          );
        }

        if (!trimmed) return <div key={idx} className="h-1"></div>;

        return <p key={idx} className="leading-relaxed">{formatInline(line)}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const chatScrollPos = useRef<number>(0);

  // Persistence for scroll position
  useEffect(() => {
    if (isOpen && scrollRef.current) {
      if (chatScrollPos.current > 0) {
        scrollRef.current.scrollTop = chatScrollPos.current;
      } else {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [isOpen]);

  const handleScroll = () => {
    if (scrollRef.current) {
      chatScrollPos.current = scrollRef.current.scrollTop;
    }
  };

  useEffect(() => {
    if (isOpen && scrollRef.current && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.role === 'user') {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages, isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          proposals.push({
            ...a,
            id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
            applied: false
          });
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => item !== null && item !== undefined);

      const contextSummary = safeData.map(i => ({
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        rpn: i.rpn
      }));

      const prompt = `
        Existing Analysis Data: ${JSON.stringify(contextSummary.slice(-15))}
        User Request: ${userMsg}

        RELIABILITY ENGINEERING REQUIREMENTS (SAE JA1011 / ISO 14224):
        1. If adding a component/section, perform a FULL FMEA. Propose MULTIPLE items (e.g. 4-8 items for a subsystem).
        2. Assign precise 'Component' names for every row.
        3. 'Failure Mode' MUST be '[Mechanism] due to [Cause]'. Example: 'Surface fatigue due to cyclic loading'.
        4. Tasks must be technically specific (e.g., 'Acoustic emissions monitoring' vs 'Check pump').
        5. For ADD: Include ALL fields: component, function, functionalFailure, failureMode, failureEffect, consequenceCategory, iso14224Code, criticality, severity, occurrence, detection, maintenanceTask, interval, taskType.
        6. Format your changes inside <ACTION>[{...}, {...}]</ACTION> tags.
        7. Maintain the same level of granular detail as a professional RCM study.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are a Senior Reliability Engineer. You only provide high-quality, technically accurate FMEA/RCM analysis. You never provide generic placeholders. You analyze failure physics (bearings, electrical, structures) and propose professional maintenance intervals based on standard P-F curves."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Proposals generated.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Engineering logic service currently unavailable." }]);
    } finally {
      setIsLoading(false);
    }
  }

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item?.component || 'New Component',
        function: proposal.item?.function || 'Perform intended work',
        functionalFailure: proposal.item?.functionalFailure || 'Total loss of function',
        failureMode: proposal.item?.failureMode || 'Wear due to usage',
        failureEffect: proposal.item?.failureEffect || 'System downtime',
        consequenceCategory: proposal.item?.consequenceCategory || 'Evident - Operational',
        iso14224Code: proposal.item?.iso14224Code || 'Wear',
        criticality: proposal.item?.criticality || 'Medium',
        severity: proposal.item?.severity || 5,
        occurrence: proposal.item?.occurrence || 3,
        detection: proposal.item?.detection || 3,
        rpn: (proposal.item?.severity || 5) * (proposal.item?.occurrence || 3) * (proposal.item?.detection || 3),
        maintenanceTask: proposal.item?.maintenanceTask || 'Inspection',
        interval: proposal.item?.interval || 'Monthly',
        taskType: (proposal.item?.taskType as any) || 'Condition Monitoring',
        ...proposal.item,
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && (proposal.item?.id || proposal.item?.component)) {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item.component;
        if (isMatch) {
          const updated = { ...item, ...proposal.item };
          updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item?.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    const newMessages = [...messages];
    newMessages[messageIndex].proposals = message.proposals.map(p => 
      p.id === proposalId ? { ...p, applied: true } : p
    );
    setMessages(newMessages);
  };

  const applyAllActions = (messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const unapplied = message.proposals.filter(p => !p.applied);
    if (unapplied.length === 0) return;

    let newData = data ? [...data] : [];

    unapplied.forEach(proposal => {
      if (proposal.type === 'ADD') {
        const newItem: RCMItem = {
          id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          component: proposal.item?.component || 'New Component',
          function: proposal.item?.function || 'Perform intended work',
          functionalFailure: proposal.item?.functionalFailure || 'Total loss of function',
          failureMode: proposal.item?.failureMode || 'Wear due to usage',
          failureEffect: proposal.item?.failureEffect || 'System downtime',
          consequenceCategory: proposal.item?.consequenceCategory || 'Evident - Operational',
          iso14224Code: proposal.item?.iso14224Code || 'Wear',
          criticality: proposal.item?.criticality || 'Medium',
          severity: proposal.item?.severity || 5,
          occurrence: proposal.item?.occurrence || 3,
          detection: proposal.item?.detection || 3,
          rpn: (proposal.item?.severity || 5) * (proposal.item?.occurrence || 3) * (proposal.item?.detection || 3),
          maintenanceTask: proposal.item?.maintenanceTask || 'Inspection',
          interval: proposal.item?.interval || 'Monthly',
          taskType: (proposal.item?.taskType as any) || 'Condition Monitoring',
          ...proposal.item,
        };
        newData.push(newItem);
      } 
      else if (proposal.type === 'UPDATE' && (proposal.item?.id || proposal.item?.component)) {
        newData = newData.map(item => {
          const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item.component;
          if (isMatch) {
            const updated = { ...item, ...proposal.item };
            updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
            return updated;
          }
          return item;
        });
      } 
      else if (proposal.type === 'DELETE' && proposal.item?.id) {
        newData = newData.filter(item => item && item.id !== proposal.item.id);
      }
    });

    onUpdate(newData);

    const newMessages = [...messages];
    newMessages[messageIndex].proposals = message.proposals.map(p => ({ ...p, applied: true }));
    setMessages(newMessages);
  };

  const renderProposalsSection = (message: Message, messageIndex: number) => {
    if (!message.proposals || message.proposals.length === 0) return null;
    const unappliedCount = message.proposals.filter(p => !p.applied).length;

    return (
      <div className="mt-4 w-full space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="flex items-center justify-between px-2 mb-2">
          <h5 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <ListChecks size={14} /> FMEA Draft Items ({message.proposals.length})
          </h5>
          {unappliedCount > 1 && (
            <button 
              onClick={() => applyAllActions(messageIndex)}
              className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2.5 py-1.5 rounded-lg hover:bg-indigo-100 transition-all flex items-center gap-1.5 border border-indigo-100 shadow-sm"
            >
              <CheckCircle2 size={12} /> Implement All
            </button>
          )}
        </div>

        <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
          {message.proposals.map((p) => (
            <div 
              key={p.id} 
              className={`bg-white border rounded-2xl p-4 shadow-sm transition-all border-l-4 ${
                p.applied ? 'border-emerald-500 bg-emerald-50/20' : 
                p.type === 'ADD' ? 'border-indigo-500' : 
                p.type === 'UPDATE' ? 'border-amber-500' : 'border-red-500'
              }`}
            >
              <div className="flex justify-between items-start gap-3">
                 <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1.5">
                      <span className={`text-[9px] font-extrabold uppercase tracking-tighter px-1.5 py-0.5 rounded ${
                        p.applied ? 'bg-emerald-500 text-white' : 
                        p.type === 'ADD' ? 'bg-indigo-600 text-white' : 
                        p.type === 'UPDATE' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                      }`}>
                        {p.applied ? 'Active' : p.type}
                      </span>
                      <span className="text-[12px] font-extrabold text-slate-900 truncate block">{p.item.component || 'Asset Component'}</span>
                    </div>

                    <div className="space-y-2">
                      <div className="text-[11px] font-medium text-slate-600 leading-snug line-clamp-2">
                        {p.item.failureMode}
                      </div>

                      {!p.applied && (
                        <div className="flex items-center gap-3 pt-1 border-t border-slate-100 mt-1">
                          <div className="flex items-center gap-1 text-[10px] font-bold text-slate-400">
                            <AlertTriangle size={10} /> RPN: <span className="text-slate-800">{(p.item.severity || 1) * (p.item.occurrence || 1) * (p.item.detection || 1)}</span>
                          </div>
                          <div className="flex items-center gap-1 text-[10px] font-bold text-slate-400">
                            <Wrench size={10} /> <span className="text-indigo-600">{p.item.taskType}</span>
                          </div>
                        </div>
                      )}
                    </div>
                 </div>

                 {!p.applied ? (
                   <button 
                     onClick={() => applySingleAction(p.id, messageIndex)}
                     className="p-2 bg-slate-900 text-white rounded-xl hover:bg-indigo-600 transition-all shrink-0 shadow-lg shadow-slate-200 group/btn"
                     title="Add to study"
                   >
                     <Plus size={18} className="group-hover/btn:scale-110 transition-transform" />
                   </button>
                 ) : (
                   <div className="p-2 bg-emerald-100 text-emerald-600 rounded-xl shrink-0">
                      <Check size={18} />
                   </div>
                 )}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[520px] h-[680px] bg-white rounded-[2rem] shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
          <div className="bg-slate-900 p-6 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-indigo-500/20 rounded-2xl border border-indigo-500/30 shadow-inner"><Bot size={24} className="text-indigo-300" /></div>
              <div>
                <h3 className="font-bold text-lg tracking-tight leading-none">Reliability Co-pilot</h3>
                <div className="flex items-center gap-2 mt-2">
                   <div className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse"></div>
                   <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Expert Consultation Active</span>
                </div>
              </div>
            </div>
            <button 
              onClick={() => setIsOpen(false)} 
              className="hover:bg-white/10 p-2 rounded-full transition-colors"
            >
              <ChevronDown size={28} />
            </button>
          </div>

          <div 
            ref={scrollRef} 
            onScroll={handleScroll}
            className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50 custom-scrollbar"
          >
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-6">
                <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center shadow-sm -rotate-6"><Sparkles size={40} /></div>
                <div className="space-y-3">
                  <p className="text-xl font-extrabold text-slate-900 tracking-tight">Advanced RCM Expert</p>
                  <p className="text-[13px] text-slate-500 leading-relaxed px-8">
                    I can perform detailed FMEA for new sections, refine failure effects, or suggest optimized intervals based on reliability standards.
                  </p>
                  <div className="pt-4 flex flex-wrap justify-center gap-2">
                    <span className="px-3 py-1.5 bg-white border border-slate-200 rounded-lg text-[10px] font-bold text-slate-500">ISO 14224</span>
                    <span className="px-3 py-1.5 bg-white border border-slate-200 rounded-lg text-[10px] font-bold text-slate-500">SAE JA1011</span>
                  </div>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[95%] p-5 rounded-3xl text-[14px] shadow-sm leading-relaxed ${
                  m.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-br-none font-medium' 
                    : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>

                {renderProposalsSection(m, i)}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 p-4 rounded-3xl rounded-bl-none shadow-sm flex items-center gap-4">
                  <div className="flex gap-1.5">
                    <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce"></div>
                  </div>
                  <span className="text-[11px] font-extrabold text-slate-400 uppercase tracking-widest">Performing Analysis</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-6 bg-white border-t border-slate-100">
            <div className="flex gap-4">
              <input 
                type="text" 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                placeholder="Suggest a new subsystem or refinement..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4.5 text-[14px] focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder:text-slate-400 font-medium"
              />
              <button 
                onClick={handleSend} 
                disabled={!input.trim() || isLoading} 
                className="p-4.5 bg-indigo-600 text-white rounded-2xl hover:bg-indigo-700 active:scale-95 disabled:opacity-50 transition-all shadow-xl shadow-indigo-100"
              >
                <Send size={24} />
              </button>
            </div>
          </div>
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)} 
        className={`w-16 h-16 rounded-full flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 ${isOpen ? 'bg-slate-900' : 'bg-indigo-600'}`}
      >
        {isOpen ? <X size={28} /> : <MessageSquare size={28} />}
        {!isOpen && <div className="absolute top-0 right-0 w-4 h-4 bg-emerald-500 border-2 border-white rounded-full"></div>}
      </button>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { 
  MessageSquare, X, Send, Loader2, Bot, Sparkles, ChevronDown, 
  Plus, Trash2, RefreshCw, Check, Info, ListChecks, CheckCircle2,
  AlertTriangle, Wrench
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
}

/**
 * FormattedMessage component to handle technical text organization
 */
const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();

        const formatInline = (content: string) => {
          return content.split(/(\*\*.*?\*\*)/g).map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={idx + '-' + i} className="font-bold">{part.slice(2, -2)}</strong>;
            }
            return part;
          });
        };

        if (trimmed.startsWith('###')) {
          return (
            <div key={idx} className="mt-4 mb-1">
              <h4 className={`font-bold text-sm ${role === 'model' ? 'text-indigo-700' : 'text-white underline'}`}>
                {formatInline(trimmed.replace(/^###\s*/, ''))}
              </h4>
            </div>
          );
        }

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          const content = trimmed.replace(/^[*|-]\s*/, '');
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 mt-1.5 w-1 h-1 rounded-full bg-current ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}></span>
              <span className="flex-1">{formatInline(content)}</span>
            </div>
          );
        }

        const numMatch = trimmed.match(/^(\d+)\.\s(.*)/);
        if (numMatch) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 font-bold text-[10px] mt-0.5 ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}>
                {numMatch[1]}.
              </span>
              <span className="flex-1">{formatInline(numMatch[2])}</span>
            </div>
          );
        }

        if (!trimmed) return <div key={idx} className="h-1"></div>;

        return <p key={idx} className="leading-relaxed">{formatInline(line)}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const chatScrollPos = useRef<number>(0);

  // Persistence logic for the chat scroll position
  useEffect(() => {
    if (isOpen && scrollRef.current) {
      if (chatScrollPos.current > 0) {
        scrollRef.current.scrollTop = chatScrollPos.current;
      } else {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [isOpen]);

  const handleScroll = () => {
    if (scrollRef.current) {
      chatScrollPos.current = scrollRef.current.scrollTop;
    }
  };

  // Auto-scroll on new user messages
  useEffect(() => {
    if (isOpen && scrollRef.current && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.role === 'user') {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages, isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object') {
            proposals.push({
              ...a,
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              applied: false,
              item: a.item || {} // Ensure item object exists defensively
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => !!item);

      const contextSummary = safeData.map(i => ({
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        rpn: i.rpn
      }));

      const prompt = `
        Current Analysis Context (Last 20 Items): ${JSON.stringify(contextSummary.slice(-20))}
        User Request: ${userMsg}

        EXPERT RELIABILITY REQUIREMENTS:
        1. If a new system/sub-system is requested, you must DECOMPOSE it into its critical components.
        2. Perform a HIGH-FIDELITY FMEA for the new section (generate 4-8 distinct rows for a new assembly).
        3. Every item must have a specific 'Component' name.
        4. Failure Mode format: '[Mechanism] due to [Cause]'. Example: 'Bearing surface fatigue due to lubrication starvation'.
        5. For each item, specify professional S, O, D scores (1-10) and ISO 14224 mechanism codes.
        6. Propose a balanced mix of tasks (Predictive CBM, Proactive Time-Based).
        7. Wrap all items in ONE <ACTION>[{...}, {...}]</ACTION> tag.
        8. For ADD: You must provide ALL RCMItem fields except 'id' and 'rpn'.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are a Senior Reliability Lead. You follow SAE JA1011 standards. You provide deep engineering value, not placeholders. When users ask for complex additions, provide a comprehensive decomposition with high-quality FMEA modes that match the professional detail of the existing study."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Engineering analysis integrated.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Engineering logic service currently unavailable. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'New Component',
        function: proposal.item.function || 'Component Function',
        functionalFailure: proposal.item.functionalFailure || 'Functional Failure',
        failureMode: proposal.item.failureMode || 'Failure mechanism',
        failureEffect: proposal.item.failureEffect || 'System effect',
        consequenceCategory: proposal.item.consequenceCategory || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'Wear',
        criticality: proposal.item.criticality || 'Medium',
        severity: proposal.item.severity || 5,
        occurrence: proposal.item.occurrence || 3,
        detection: proposal.item.detection || 3,
        rpn: (proposal.item.severity || 5) * (proposal.item.occurrence || 3) * (proposal.item.detection || 3),
        maintenanceTask: proposal.item.maintenanceTask || 'Inspection',
        interval: proposal.item.interval || 'Monthly',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        ...proposal.item,
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && (proposal.item.id || proposal.item.component)) {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
        if (isMatch) {
          const updated = { ...item, ...proposal.item };
          updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
