import { GoogleGenAI } from "@google/genai";

interface OperationalContextBuilderProps {
  isOpen: boolean;
  onClose: () => void;
  onComplete: (context: string) => void;
}

interface Message {
  role: 'user' | 'assistant';
  content: string;
}

export const OperationalContextBuilder: React.FC<OperationalContextBuilderProps> = ({ isOpen, onClose, onComplete }) => {
  const [messages, setMessages] = useState<Message[]>([
    { 
      role: 'assistant', 
