export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null
): Promise<RCMItem[]> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable is not set.");
    }

    const ai = new GoogleGenAI({ apiKey });

    const parts: any[] = [];

    // Add file content if available
    if (fileData) {
      parts.push({
        inlineData: {
          mimeType: fileData.mimeType,
          data: fileData.data,
        },
      });
      parts.push({
        text: "Analyze the technical context in this document to identify the core components and sub-assemblies."
      });
    }

    // Add manual text context
    if (contextText) {
      parts.push({
        text: `Operational Context provided by user:\n${contextText}`
      });
    }

    parts.push({
      text: `Perform a professional-grade, HIGH-STAKES Reliability Centered Maintenance (RCM) and FMECA analysis.

      GOAL: Provide a comprehensive and rigorous analysis. Ensure that risk is assessed with a safety-first mindset.

      CRITICAL RPN GUIDELINES:
      - We require a realistic and rigorous risk assessment. 
      - Do NOT default to middle-of-the-road scores (like 5/3/3). 
      - If a failure has safety, environmental, or major production implications, the Severity MUST be 8-10.
      - If a failure is common in industrial environments (like bearing wear or seal leakage), Occurrence MUST reflect that (e.g., 6-9).
      - If a failure is internal and requires specialized equipment to detect, Detection MUST be high (e.g., 8-10).
      - Aim for RPN numbers that correctly identify high-criticality items, often resulting in scores exceeding 200-300 for significant risks.

      TECHNICAL REQUIREMENTS:
      1. **Strategic Mix**: Include a balanced variety of tasks. Combine 'Condition Monitoring' (Predictive) with 'Time-Based' (Proactive) tasks where wear-out characteristics exist. Use 'Failure Finding' for hidden protective functions.
      2. **Granular Decomposition**: Identify risks for key sub-components (Bearings, Seals, Windings, Couplings, etc.).
      3. **Failure Mechanisms**: Identify technical mechanisms such as Fatigue, Wear, Corrosion, Insulation breakdown, and Alignment issues.
      4. **Task Selection**: Propose actionable maintenance such as Vibration analysis, Thermography, Oil sampling, Scheduled overhauls, and Calibration.
      5. **No Hallucinations**: Focus on technically plausible failures based on the provided context.
      6. **Format**: Each unique [Mechanism] due to [Cause] must be its own row.

      Standard Compliance: SAE JA1011 RCM principles and ISO 14224 taxonomy.`
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: rcmSchema,
        seed: 42, 
        thinkingConfig: {
          thinkingBudget: 16000 
        },
        systemInstruction: `You are a Senior Reliability and Safety Engineer. You provide rigorous, high-fidelity RCM reports. 
        Your risk assessments are realistic and do not shy away from assigning high S, O, and D scores when technical conditions warrant them. 
        You prioritize safety and availability. Your goal is to identify critical risks clearly so they stand out in a risk matrix.`
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response generated from Gemini.");
    }

    const rawData = JSON.parse(text) as Omit<RCMItem, 'id' | 'rpn'>[];

    return rawData.map((item, index) => {
      const s = item.severity || 8;
      const o = item.occurrence || 5;
      const d = item.detection || 5;
      return { 
        ...item, 
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        id: `rcm-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 9)}` 
      };
    });

  } catch (error) {
    console.error("RCM Generation Error:", error);
    throw error;
  }
};

