    return rawData.map((item, index) => {
      const s = item.severity || 8;
      const o = item.occurrence || 5;
      const d = item.detection || 7;
      return { 
        ...item, 
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        id: `rcm-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 9)}` 
      };
    });

  } catch (error) {
    console.error("RCM Generation Error:", error);
    throw error;
  }
};

