                 {barFilter && <span className="text-[10px] bg-indigo-500/20 px-2 py-0.5 rounded border border-indigo-500/30">Chart Isolation: On</span>}
                 {searchFilters.component && <span className="text-[10px] bg-slate-700 px-2 py-0.5 rounded border border-slate-600">Comp: {searchFilters.component}</span>}
                 {searchFilters.function && <span className="text-[10px] bg-slate-700 px-2 py-0.5 rounded border border-slate-600">Func: {searchFilters.function}</span>}
                 {searchFilters.failureMode && <span className="text-[10px] bg-slate-700 px-2 py-0.5 rounded border border-slate-600">Fail: {searchFilters.failureMode}</span>}
                 {searchFilters.consequenceCategory && <span className="text-[10px] bg-slate-700 px-2 py-0.5 rounded border border-slate-600">Cons: {searchFilters.consequenceCategory}</span>}
                 {searchFilters.iso14224Code && <span className="text-[10px] bg-slate-700 px-2 py-0.5 rounded border border-slate-600">ISO: {searchFilters.iso14224Code}</span>}
               </div>
             </div>
             <button onClick={clearAllFilters} className="text-xs bg-white text-slate-900 px-3 py-1.5 rounded font-bold hover:bg-slate-200">Clear All Filters</button>
           </div>
        )}

        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/80 border-b border-slate-200 text-[11px] font-bold uppercase tracking-wider text-slate-500 sticky top-0 z-10">
                <th className="px-6 py-4 min-w-[150px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('component')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">Component {renderSortIcon('component')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Search..." value={searchFilters.component} onChange={(e) => handleSearchChange('component', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all" /></div></div></th>
                <th className="px-6 py-4 min-w-[150px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('consequenceCategory')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">Consequence {renderSortIcon('consequenceCategory')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Search..." value={searchFilters.consequenceCategory} onChange={(e) => handleSearchChange('consequenceCategory', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all" /></div></div></th>
                <th className="px-6 py-4 min-w-[120px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('iso14224Code')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">ISO 14224 {renderSortIcon('iso14224Code')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Search..." value={searchFilters.iso14224Code} onChange={(e) => handleSearchChange('iso14224Code', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all" /></div></div></th>
                <th className="px-6 py-4 min-w-[200px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('failureMode')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">Failure Mode {renderSortIcon('failureMode')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Search..." value={searchFilters.failureMode} onChange={(e) => handleSearchChange('failureMode', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none" /></div></div></th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/50 border-l border-slate-200">S</th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/50">O</th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/50">D</th>
                <th className="px-4 py-4 min-w-[100px] text-left bg-slate-100/50 border-r border-slate-200"><button onClick={() => requestSort('rpn')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">RPN {renderSortIcon('rpn')}</button></th>
                <th className="px-6 py-4 min-w-[180px]">Proposed Task</th>
                <th className="px-6 py-4 w-16 text-center">Insp.</th>
                <th className="px-6 py-4 w-20 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm bg-white">
              {processedData.length === 0 ? (
                <tr><td colSpan={13} className="text-center py-20 bg-slate-50/30"><div className="flex flex-col items-center gap-2 text-slate-400"><FilterX size={48} strokeWidth={1} /><p className="font-medium">No matches found for active filters.</p><button onClick={clearAllFilters} className="text-indigo-600 text-xs hover:underline mt-2">Clear all filters</button></div></td></tr>
              ) : (
                processedData.map((item) => {
                  if (!item) return null;
                  const isEditing = editingId === item.id; const isRegenerating = regeneratingIds.has(item.id);
                  if (isEditing && editForm) {
                    return (
                      <tr key={item.id} className="bg-indigo-50/30 ring-2 ring-indigo-500/20 z-10 relative">
                        <td className="px-6 py-4 align-top"><input type="text" value={editForm.component} onChange={(e) => handleChange('component', e.target.value)} className="w-full px-2 py-1 border rounded" /></td>
                        <td className="px-6 py-4 align-top">
                          <select 
                            value={editForm.consequenceCategory} 
                            onChange={(e) => handleChange('consequenceCategory', e.target.value)}
                            className="w-full px-2 py-1 border rounded text-xs"
                          >
                            {CONSEQUENCE_LABELS.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                          </select>
                        </td>
                        <td className="px-6 py-4 align-top"><input type="text" value={editForm.iso14224Code} onChange={(e) => handleChange('iso14224Code', e.target.value)} className="w-full px-2 py-1 border rounded text-xs" /></td>
                        <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={2} value={editForm.failureMode} onChange={(e) => handleChange('failureMode', e.target.value)} className="w-full px-2 py-1 border rounded" /><textarea rows={3} value={editForm.failureEffect} onChange={(e) => handleChange('failureEffect', e.target.value)} className="w-full px-2 py-1 border rounded" /></div></td>
                        <td className="px-2 py-4 align-top bg-white/50 border-l"><input type="number" min="1" max="10" value={editForm.severity} onChange={(e) => handleChange('severity', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.occurrence} onChange={(e) => handleChange('occurrence', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.detection} onChange={(e) => handleChange('detection', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-4 py-4 align-top text-center font-bold bg-white/50 border-r">{(editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1)}</td>
                        <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={3} value={editForm.maintenanceTask} onChange={(e) => handleChange('maintenanceTask', e.target.value)} className="w-full border rounded" /><input type="text" value={editForm.interval} onChange={(e) => handleChange('interval', e.target.value)} className="w-full border rounded" /></div></td>
                        <td className="px-6 py-4 align-top text-center text-slate-300"><File size={20} className="mx-auto" /></td>
                        <td className="px-6 py-4 align-top text-right"><div className="flex flex-col gap-2 items-end"><button onClick={handleSave} className="p-2 bg-emerald-500 text-white rounded"><Save size={16} /></button><button onClick={handleCancel} className="p-2 bg-slate-200 text-slate-600 rounded"><X size={16} /></button></div></td>
                      </tr>
                    );
                  }
                  const rpn = item.rpn || 0; const rpnStyle = getRPNColorStyle(rpn);
                  const consCat = item.consequenceCategory || '';
                  return (
                    <tr key={item.id} className={`group hover:bg-slate-50 ${isRegenerating ? 'opacity-60 bg-slate-50' : ''} ${barFilter === item.id ? 'bg-indigo-50/50' : ''}`}>
                      <td className="px-6 py-4 font-medium align-top leading-tight text-xs">
                        <div className="flex items-center gap-2">
                           <span className="flex-1">{item.component}</span>
                           <button 
                             onClick={() => setSelectedIntel(item)}
                             className="p-1 text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 rounded-md transition-all opacity-0 group-hover:opacity-100"
                             title="Physical Component Intel"
                           >
                             <Info size={14} />
                           </button>
                        </div>
                      </td>
                      <td className="px-6 py-4 align-top">
                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-full border ${consCat.includes('Hidden') ? 'bg-orange-50 text-orange-700 border-orange-200' : 'bg-blue-50 text-blue-700 border-blue-200'}`}>
                          {consCat}
                        </span>
                      </td>
                      <td className="px-6 py-4 align-top">
                        <span className="text-[10px] font-mono font-bold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded border border-indigo-100 uppercase">
                          {item.iso14224Code}
                        </span>
                      </td>
                      <td className="px-6 py-4 align-top"><div className="space-y-2"><div className="font-semibold text-[11px] border p-1 rounded inline-block bg-white shadow-sm leading-tight">{item.failureMode}</div><div className="text-slate-500 text-[10px] leading-relaxed line-clamp-2">{item.failureEffect}</div></div></td>
                      <td className="px-2 py-4 align-middle text-center border-l"><span className={getScoreColor(item.severity || 0)}>{item.severity || 0}</span></td>
                      <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.occurrence || 0)}>{item.occurrence || 0}</span></td>
                      <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.detection || 0)}>{item.detection || 0}</span></td>
                      <td className="px-4 py-4 align-middle border-r"><div className="flex flex-col gap-1"><span className={`text-xs font-bold ${rpnStyle.text}`}>{rpn}</span><div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full ${rpnStyle.bar}`} style={{width: `${Math.min((rpn/400)*100, 100)}%`}}></div></div></div></td>
                      <td className="px-6 py-4 align-top"><div className="font-medium text-xs leading-tight">{item.maintenanceTask}</div><div className="text-[10px] text-slate-400 font-mono mt-1">{item.interval}</div></td>
                      <td className="px-6 py-4 align-middle text-center">
                         {isRegenerating ? <RefreshCw size={20} className="animate-spin text-indigo-500 mx-auto" /> : item.inspectionSheet ? <button onClick={() => setViewSheet({ item })} className="text-emerald-500 hover:scale-110 transition-transform"><FileCheck size={22} /></button> : <button onClick={() => handleGenerateSingleSheet(item)} className="text-slate-300 hover:text-indigo-500"><File size={22} /></button>}
                      </td>
                      <td className="px-6 py-4 align-middle text-right opacity-0 group-hover:opacity-100 transition-opacity"><div className="flex justify-end gap-1"><button onClick={() => handleEdit(item)} className="p-1 text-slate-400 hover:text-indigo-600"><Pencil size={16} /></button><button onClick={() => handleDelete(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16} /></button></div></td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
  }, [results, contextText, fileData, studyName, currentStudyId]);

  // Load studies from DB on mount
  useEffect(() => {
    const initData = async () => {
      try {
        const legacyData = localStorage.getItem('rcm_studies');
        if (legacyData) {
          try {
            const parsed = JSON.parse(legacyData) as SavedStudy[];
            if (Array.isArray(parsed) && parsed.length > 0) {
              await Promise.all(parsed.map(study => saveStudyToDB(study)));
              localStorage.removeItem('rcm_studies');
            }
          } catch (e) {
            console.warn("Failed to parse legacy data", e);
          }
        }
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 1 minute)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      if (resultsRef.current && resultsRef.current.length > 0) {
        console.log("Auto-saving progress...");
        handleSaveStudy();
      }
    }, 60000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type,
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setResults(null);
    setHistory([]);

    try {
      const data = await generateRCMAnalysis(contextText, fileData);
      setResults(data);
    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async () => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: Date.now(),
      items: currentResults || [],
      contextText: currentContext,
      fileName: currentFile?.name
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);
    } catch (e) {
      console.error("Save failed", e);
      setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items);
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]); // Keep last 30 states
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">

      {/* Modals */}
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} />
      <OperationalContextBuilder 
        isOpen={showContextBuilder} 
        onClose={() => setShowContextBuilder(false)} 
        onComplete={(builtContext) => setContextText(builtContext)} 
      />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} />

      {/* AI Copilot - Minimal floating UI */}
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`
        fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <Sidebar 
          studies={savedStudies}
          currentStudyId={currentStudyId}
          onSelect={handleLoadStudy}
          onDelete={handleDeleteStudy}
          onNew={handleNewStudy}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        {/* Header */}
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">

            <div className="flex items-center gap-6 min-w-0">
              <button 
                className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden"
                onClick={() => setIsSidebarOpen(true)}
              >
                <Menu size={24} />
              </button>

              {/* STUNNING BRAND SECTION */}
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6">
                  <Cpu size={22} className="text-indigo-400 group-hover:text-white" />
                </div>
                <div className="flex flex-col">
                  <span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span>
                  <div className="flex items-center gap-1 mt-1">
                    <span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span>
                    <span className="text-[11px] font-black text-slate-400 leading-none">PRO</span>
                  </div>
                </div>
              </div>

              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                    <input 
                      type="text" 
                      value={studyName}
                      onChange={(e) => setStudyName(e.target.value)}
                      placeholder="Untitled Analysis"
                      className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate"
                    />
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">
                   {currentStudyId ? "System Repository" : "Temporary Workspace"}
                 </p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button
                  onClick={() => setShowSODReference(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"
                >
                  <BookOpen size={16} />
                  S/O/D Guide
                </button>
                <button
                  onClick={() => setShowDecisionLogic(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"
                >
                  <GitBranch size={16} />
                  Logic Tree
                </button>
              </div>

              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">
                {justSaved ? (
                  <span className="text-emerald-600 flex items-center gap-1.5"><Check size={14} strokeWidth={3} /> Synced</span>
                ) : (
                   <span className="text-slate-300">{results ? 'Local draft' : ''}</span>
                )}
              </div>

              <div className="flex items-center gap-2">
                <button
                  onClick={handleUndo}
                  disabled={history.length === 0}
                  className={`p-2.5 rounded-xl transition-all ${
                    history.length > 0 
                      ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' 
                      : 'text-slate-200 cursor-not-allowed'
                  }`}
                  title="Undo last action"
                >
                  <Undo2 size={20} />
                </button>

                <button
                  onClick={handleSaveStudy}
                  disabled={!results && !contextText}
                  className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-xl
                    ${justSaved 
                      ? 'bg-emerald-50 text-emerald-600 border border-emerald-200 shadow-emerald-50' 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'
                    }
                    ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}
                  `}
                >
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">
                  Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.
                </p>
              </div>
            )}

            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button
                  onClick={() => setActiveTab('manual')}
                  className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${
                    activeTab === 'manual' 
                      ? 'border-indigo-600 text-indigo-600' 
                      : 'border-transparent text-slate-400 hover:text-slate-600'
                  }`}
                >
                  <Type size={14} />
                  Manual Synthesis
                </button>
                <button
                  onClick={() => setActiveTab('upload')}
                  className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${
                    activeTab === 'upload' 
                      ? 'border-indigo-600 text-indigo-600' 
                      : 'border-transparent text-slate-400 hover:text-slate-600'
                  }`}
                >
                  <Upload size={14} />
                  Knowledge Upload
                </button>
              </div>

              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">
                        Operational Context Description
                      </label>
                      <button 
                        onClick={() => setShowContextBuilder(true)}
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-indigo-50 text-indigo-600 rounded-xl text-[10px] font-black border border-indigo-100 hover:bg-indigo-100 transition-all shadow-sm uppercase tracking-tighter"
                      >
                        <Sparkles size={14} className="fill-indigo-500" />
                        Context Wizard
                      </button>
                    </div>
                    <textarea
                      className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner"
                      placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..."
                      value={contextText}
                      onChange={(e) => setContextText(e.target.value)}
                    />
                  </div>
                )}

                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group">
                        <input 
                          type="file" 
                          id="file-upload"
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                          accept=".txt,.pdf,.png,.jpg,.jpeg"
                          onChange={handleFileUpload}
                        />
                        {!fileData ? (
                          <>
                            <div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500">
                              <Upload size={28} />
                            </div>
                            <p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p>
                            <p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, TXT and Images</p>
                          </>
                        ) : (
                          <div className="flex items-center gap-5 w-full max-w-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95">
                            <div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner">
                              <FileCheck size={28} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p>
                            </div>
                            <button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all">
                              <Trash2 size={20} />
                            </button>
                          </div>
                        )}
                     </div>
                  </div>
                )}

                {error && (
                  <div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500">
                    <AlertTriangle size={18} />
                    {error}
                  </div>
                )}

                <div className="mt-8 flex justify-end">
                  <button
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-1'}`}
                  >
                    {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Zap size={20} className="fill-white" />}
                    {isLoading ? "Running Intelligence Engine..." : "Initiate FMEA Synthesis"}
                  </button>
                </div>
              </div>
            </div>

            {results && (
              <AnalysisResult 
                data={results} 
                onUpdate={handleResultsUpdate}
              />
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
  }, [results, contextText, fileData, studyName, currentStudyId]);

  // Load studies from DB on mount
  useEffect(() => {
    const initData = async () => {
      try {
        const legacyData = localStorage.getItem('rcm_studies');
        if (legacyData) {
          try {
            const parsed = JSON.parse(legacyData) as SavedStudy[];
            if (Array.isArray(parsed) && parsed.length > 0) {
              await Promise.all(parsed.map(study => saveStudyToDB(study)));
              localStorage.removeItem('rcm_studies');
            }
          } catch (e) {
            console.warn("Failed to parse legacy data", e);
          }
        }
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 1 minute)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      if (resultsRef.current && resultsRef.current.length > 0) {
        console.log("Auto-saving progress...");
        handleSaveStudy();
      }
    }, 60000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type,
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setResults(null);
    setHistory([]);

    try {
      const data = await generateRCMAnalysis(contextText, fileData);
      setResults(data);
    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async () => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: Date.now(),
      items: currentResults || [],
      contextText: currentContext,
      fileName: currentFile?.name
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);
    } catch (e) {
      console.error("Save failed", e);
      setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items);
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]); // Keep last 30 states
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">

      {/* Modals */}
      <SODReference 
        isOpen={showSODReference} 
        onClose={() => setShowSODReference(false)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
      />
      <OperationalContextBuilder 
        isOpen={showContextBuilder} 
        onClose={() => setShowContextBuilder(false)} 
        onComplete={(builtContext) => setContextText(builtContext)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
      />
      <DecisionLogicModal 
        isOpen={showDecisionLogic} 
        onClose={() => setShowDecisionLogic(false)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
      />

      {/* AI Copilot - Minimal floating UI */}
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`
        fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <Sidebar 
          studies={savedStudies}
          currentStudyId={currentStudyId}
          onSelect={handleLoadStudy}
          onDelete={handleDeleteStudy}
          onNew={handleNewStudy}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        {/* Header */}
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">

            <div className="flex items-center gap-6 min-w-0">
              <button 
                className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden"
                onClick={() => setIsSidebarOpen(true)}
              >
                <Menu size={24} />
              </button>

              {/* STUNNING BRAND SECTION */}
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6">
                  <Cpu size={22} className="text-indigo-400 group-hover:text-white" />
                </div>
                <div className="flex flex-col">
                  <span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span>
                  <div className="flex items-center gap-1 mt-1">
                    <span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span>
                    <span className="text-[11px] font-black text-slate-400 leading-none">PRO</span>
                  </div>
                </div>
              </div>

              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                    <input 
                      type="text" 
                      value={studyName}
                      onChange={(e) => setStudyName(e.target.value)}
                      placeholder="Untitled Analysis"
                      className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate"
                    />
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">
                   {currentStudyId ? "System Repository" : "Temporary Workspace"}
                 </p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button
                  onClick={() => setShowSODReference(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"
                >
                  <BookOpen size={16} />
                  S/O/D Guide
                </button>
                <button
                  onClick={() => setShowDecisionLogic(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"
                >
                  <GitBranch size={16} />
                  Logic Tree
                </button>
              </div>

              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">
                {justSaved ? (
                  <span className="text-emerald-600 flex items-center gap-1.5"><Check size={14} strokeWidth={3} /> Synced</span>
                ) : (
                   <span className="text-slate-300">{results ? 'Local draft' : ''}</span>
                )}
              </div>

              <div className="flex items-center gap-2">
                <button
                  onClick={handleUndo}
                  disabled={history.length === 0}
                  className={`p-2.5 rounded-xl transition-all ${
                    history.length > 0 
                      ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' 
                      : 'text-slate-200 cursor-not-allowed'
                  }`}
                  title="Undo last action"
                >
                  <Undo2 size={20} />
                </button>

                <button
                  onClick={handleSaveStudy}
                  disabled={!results && !contextText}
                  className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-xl
                    ${justSaved 
                      ? 'bg-emerald-50 text-emerald-600 border border-emerald-200 shadow-emerald-50' 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'
                    }
                    ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}
                  `}
                >
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">
                  Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.
                </p>
              </div>
            )}

            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button
                  onClick={() => setActiveTab('manual')}
                  className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${
                    activeTab === 'manual' 
                      ? 'border-indigo-600 text-indigo-600' 
                      : 'border-transparent text-slate-400 hover:text-slate-600'
                  }`}
                >
                  <Type size={14} />
                  Manual Synthesis
                </button>
                <button
                  onClick={() => setActiveTab('upload')}
                  className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${
                    activeTab === 'upload' 
                      ? 'border-indigo-600 text-indigo-600' 
                      : 'border-transparent text-slate-400 hover:text-slate-600'
                  }`}
                >
                  <Upload size={14} />
                  Knowledge Upload
                </button>
              </div>

              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">
                        Operational Context Description
                      </label>
                      <button 
                        onClick={() => setShowContextBuilder(true)}
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-indigo-50 text-indigo-600 rounded-xl text-[10px] font-black border border-indigo-100 hover:bg-indigo-100 transition-all shadow-sm uppercase tracking-tighter"
                      >
                        <Sparkles size={14} className="fill-indigo-500" />
                        Context Wizard
                      </button>
                    </div>
                    <textarea
                      className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner"
                      placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..."
                      value={contextText}
                      onChange={(e) => setContextText(e.target.value)}
                    />
                  </div>
                )}

                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group">
                        <input 
                          type="file" 
                          id="file-upload"
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                          accept=".txt,.pdf,.png,.jpg,.jpeg"
                          onChange={handleFileUpload}
                        />
                        {!fileData ? (
                          <>
                            <div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500">
                              <Upload size={28} />
                            </div>
                            <p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p>
                            <p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, TXT and Images</p>
                          </>
                        ) : (
                          <div className="flex items-center gap-5 w-full max-w-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95">
                            <div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner">
                              <FileCheck size={28} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p>
                            </div>
                            <button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all">
                              <Trash2 size={20} />
                            </button>
                          </div>
                        )}
                     </div>
                  </div>
                )}

                {error && (
                  <div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500">
                    <AlertTriangle size={18} />
                    {error}
                  </div>
                )}

                <div className="mt-8 flex justify-end">
                  <button
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-1'}`}
                  >
                    {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Zap size={20} className="fill-white" />}
                    {isLoading ? "Running Intelligence Engine..." : "Initiate FMEA Synthesis"}
                  </button>
                </div>
              </div>
            </div>

            {results && (
              <AnalysisResult 
                data={results} 
                onUpdate={handleResultsUpdate}
                onUndo={handleUndo}
                canUndo={history.length > 0}
              />
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

