export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  language: Language = 'en'
): Promise<RCMItem[]> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API_KEY not set");

    const ai = new GoogleGenAI({ apiKey });
    const parts: any[] = [];

    if (fileData) {
      parts.push({ inlineData: { mimeType: fileData.mimeType, data: fileData.data } });
    }
    if (contextText) {
      parts.push({ text: `Operational Context:\n${contextText}` });
    }

    parts.push({
      text: `Perform a level-4 component decomposition and COMPREHENSIVE RCM study. 
      Target: ~30 failure modes. 
      MANDATORY: Generate ALL content specifically in the following language: ${language.toUpperCase()}.
      Compliance: SAE JA1011 and ISO 14224.`
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: rcmSchema,
        seed: 42, 
        thinkingConfig: { thinkingBudget: 24000 },
        systemInstruction: `You are a Senior Maintenance Engineer. You MUST generate all technical content in ${language}. Ensure taxonomy (ISO 14224) and strategy (SAE JA1011) are respected.`
      }
    });

    const rawData = JSON.parse(response.text || "[]") as Omit<RCMItem, 'id' | 'rpn'>[];
    return rawData.map((item, index) => {
      const s = item.severity || 8;
      const o = item.occurrence || 5;
      const d = item.detection || 6;
      return { 
        ...item, 
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        id: `rcm-${Date.now()}-${index}` 
      };
    });
  } catch (error) {
    throw error;
  }
};

export const generateInspectionSheet = async (item: RCMItem, language: Language = 'en'): Promise<InspectionSheet> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API_KEY not set");
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `Create a technical inspection procedure for: ${item.maintenanceTask} on ${item.component}.
    Ensure 5 clear steps with pass/fail criteria. Output language: ${language}.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: inspectionSchema,
        seed: 42,
        thinkingConfig: { thinkingBudget: 4000 },
        systemInstruction: `Technical Procedure Author. Professional and actionable. You must write strictly in ${language}.`
      }
    });

    return JSON.parse(response.text || "{}") as InspectionSheet;
  } catch (error) {
    throw error;
  }
};

