              <button onClick={handleUndo} disabled={history.length === 0} className="p-2.5 bg-slate-50 text-slate-400 rounded-xl disabled:opacity-30"><Undo2 size={20} /></button>
              <button onClick={handleSaveStudy} className="bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-100">
                {justSaved ? <Check size={18} /> : 'Save Study'}
              </button>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-6 bg-slate-50/50">
          {!results && (
            <div className="max-w-7xl mx-auto space-y-10">
              <div className="bg-white rounded-[2rem] p-10 border border-slate-200 shadow-sm space-y-6">
                <textarea value={contextText} onChange={e => setContextText(e.target.value)} className="w-full h-64 p-8 bg-slate-50 border border-slate-200 rounded-[2.5rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-slate-800" placeholder="Operational Context..." />
                <div className="flex justify-end">
                  <button onClick={handleGenerate} disabled={isLoading} className="bg-indigo-600 text-white px-12 py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-2xl hover:-translate-y-1 transition-all flex items-center gap-3">
                    {isLoading ? <Loader2 className="animate-spin" /> : <Zap size={18} />} {isLoading ? 'Generating...' : 'Initiate Synthesis'}
                  </button>
                </div>
              </div>
            </div>
          )}
          {results && <AnalysisResult data={results} onUpdate={setResults} onUndo={handleUndo} canUndo={history.length > 0} language={language} />}
        </main>
      </div>
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={setContextText} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
    </div>
  );
};

