const getTaskImage = (task: string): string => {
  const t = (task || '').toLowerCase();
  if (t.includes('thermal') || t.includes('heat')) return 'https://images.unsplash.com/photo-1504917595217-d4dc5ebe6122?auto=format&fit=crop&w=800&q=80';
  if (t.includes('vibration') || t.includes('align')) return 'https://images.unsplash.com/photo-1581094288338-2314dddb7ece?auto=format&fit=crop&w=800&q=80';
  if (t.includes('oil') || t.includes('lubricat')) return 'https://images.unsplash.com/photo-1621905252507-b35492cc74b4?auto=format&fit=crop&w=800&q=80';
  return 'https://images.unsplash.com/photo-1565514020176-db5b550dd707?auto=format&fit=crop&w=800&q=80';
};

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

const getScoreColor = (score: number) => {
  if (score >= 8) return 'text-red-600 font-bold';
  if (score >= 5) return 'text-amber-600 font-medium';
  return 'text-slate-500';
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, onUpdate, onUndo, canUndo, language }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);

  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn'; direction: 'asc' | 'desc' }>({ key: 'rpn', direction: 'desc' });
  const [searchFilters, setSearchFilters] = useState({ component: '', function: '', failureMode: '', consequenceCategory: '', iso14224Code: '' });

  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);

  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());
  const [copied, setCopied] = useState(false);
  const [classicalCopied, setClassicalCopied] = useState(false);

  const t = translations[language] || translations.en;

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => !!item);

    if (matrixFilter) {
      result = result.filter(item => 
        (item.severity || 0) === matrixFilter.s && 
        (item.occurrence || 0) === matrixFilter.o
      );
    }

    if (barFilter) {
      result = result.filter(item => item.id === barFilter);
    }

    if (searchFilters.component) {
      result = result.filter(item => item.component.toLowerCase().includes(searchFilters.component.toLowerCase()));
    }
    if (searchFilters.failureMode) {
      result = result.filter(item => item.failureMode.toLowerCase().includes(searchFilters.failureMode.toLowerCase()));
    }
    if (searchFilters.consequenceCategory) {
      result = result.filter(item => item.consequenceCategory.toLowerCase().includes(searchFilters.consequenceCategory.toLowerCase()));
    }
    if (searchFilters.iso14224Code) {
      result = result.filter(item => item.iso14224Code.toLowerCase().includes(searchFilters.iso14224Code.toLowerCase()));
    }

    result.sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;
      if (typeof aVal === 'string' && typeof bVal === 'string') {
        return aVal.localeCompare(bVal) * multiplier;
      }
      return ((aVal as number) - (bVal as number)) * multiplier;
    });

    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  const handleCopy = async () => {
    const headers = [t.component, t.consequence, t.isoCode, t.failureMode, t.rpn, t.proposedTask, t.frequency];
    const rows = processedData.map(item => [
      item.component, item.consequenceCategory, item.iso14224Code, item.failureMode, item.rpn, item.maintenanceTask, item.interval
    ].map(v => `"${String(v).replace(/"/g, '""')}"`).join("\t"));

    await navigator.clipboard.writeText([headers.join("\t"), ...rows].join("\n"));
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleClassicalCopy = async () => {
    const headers = [t.component, t.failureMode, t.proposedTask, t.frequency, t.type, t.stepsTitle, t.actions];
    const rows: string[] = [];

    let lastComp = "";

    processedData.forEach(item => {
      const compVal = item.component === lastComp ? "" : item.component;
      lastComp = item.component;

      const steps = item.inspectionSheet?.steps || [{ step: 1, description: "" }];

      steps.forEach((s, idx) => {
        // Classical RCM Logic: Omit repetitive text in subsequent step rows for the same component/mode
        const row = [
          idx === 0 ? compVal : "",
          idx === 0 ? item.failureMode : "",
          idx === 0 ? item.maintenanceTask : "",
          idx === 0 ? item.interval : "",
          idx === 0 ? item.taskType : "",
          s.step,
          s.description
        ];
        rows.push(row.map(v => `"${String(v).replace(/"/g, '""').replace(/\t/g, ' ')}"`).join("\t"));
      });
    });

    await navigator.clipboard.writeText([headers.join("\t"), ...rows].join("\n"));
    setClassicalCopied(true);
    setTimeout(() => setClassicalCopied(false), 2000);
  };

  const handleGenerateAllSheets = async () => {
    const itemsToProcess = data.filter(item => !item.inspectionSheet);
    if (itemsToProcess.length === 0) return;
    setGeneratingSheets(true);
    setProgress({ current: 0, total: itemsToProcess.length });

    let currentData = [...data];
    for (const item of itemsToProcess) {
      try {
        const sheet = await generateInspectionSheet(item, language);
        currentData = currentData.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d);
        onUpdate([...currentData]);
      } catch (e) {}
      setProgress(p => ({ ...p, current: p.current + 1 }));
    }
    setGeneratingSheets(false);
  };

  const topRisksData = useMemo(() => {
    return data
      .sort((a, b) => (b.rpn || 0) - (a.rpn || 0))
      .slice(0, 5)
      .map(item => ({
        id: item.id,
        name: item.failureMode.length > 20 ? item.failureMode.substring(0, 20) + '...' : item.failureMode,
        rpn: item.rpn || 0
      }));
  }, [data]);

  const stats = [
    { label: t.totalFailModes, value: data.length, icon: ListChecks, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: t.maxRPN, value: Math.max(...data.map(i => i.rpn || 0), 0), icon: AlertOctagon, color: 'text-red-600', bg: 'bg-red-50' },
    { label: t.conditionMonitoring, value: data.filter(i => i.taskType === 'Condition Monitoring').length, icon: Zap, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: t.timeBased, value: data.filter(i => i.taskType === 'Time-Based').length, icon: Clock, color: 'text-purple-600', bg: 'bg-purple-50' },
    { label: t.failureFinding, value: data.filter(i => i.taskType === 'Failure Finding').length, icon: Search, color: 'text-amber-600', bg: 'bg-amber-50' },
    { label: t.runToFailure, value: data.filter(i => i.taskType === 'Run-to-Failure').length, icon: CheckCircle, color: 'text-emerald-600', bg: 'bg-emerald-50' },
  ];

  const requestSort = (key: keyof RCMItem | 'rpn') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') direction = 'desc';
    setSortConfig({ key, direction });
  };

  const renderSortIcon = (key: keyof RCMItem | 'rpn') => {
    if (sortConfig.key !== key) return <ArrowUpDown size={14} className="text-slate-300" />;
    return sortConfig.direction === 'asc' ? <ArrowUp size={14} className="text-indigo-600" /> : <ArrowDown size={14} className="text-indigo-600" />;
  };

  return (
    <div className="space-y-8 animate-fade-in relative w-full">
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-4">
        {stats.map((stat, i) => (
           <div key={i} className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow">
            <div className="flex flex-col gap-3">
              <div className={`w-10 h-10 rounded-xl ${stat.bg} ${stat.color} flex items-center justify-center shrink-0`}>
                <stat.icon size={20} />
              </div>
              <div>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-tight leading-none mb-1.5">{stat.label}</p>
                <h3 className="text-xl font-bold text-slate-800 leading-none">{stat.value}</h3>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Visual Analysis Section */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
        <div className="xl:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col">
          <div className="flex justify-between items-start mb-6">
            <div><h3 className="text-lg font-bold text-slate-800 flex items-center gap-2"><AlertTriangle size={20} className="text-orange-500" />{t.riskMatrix}</h3><p className="text-sm text-slate-500 mt-1">{t.matrixSubtitle}</p></div>
            <div className="flex gap-2 text-xs font-medium">
              <div className="flex items-center gap-1"><div className="w-3 h-3 bg-emerald-100 border border-emerald-300 rounded-sm"></div> Low</div>
              <div className="flex items-center gap-1"><div className="w-3 h-3 bg-amber-100 border border-amber-300 rounded-sm"></div> Med</div>
              <div className="flex items-center gap-1"><div className="w-3 h-3 bg-red-100 border border-red-300 rounded-sm"></div> High</div>
            </div>
          </div>
          <div className="flex-1 min-h-[300px] flex items-center justify-center p-4 relative">
             <div className="relative w-full max-w-lg aspect-square">
                <div className="grid grid-cols-10 grid-rows-10 gap-1 w-full h-full">
                   {Array.from({ length: 100 }).map((_, idx) => {
                      const x = (idx % 10) + 1; const y = 10 - Math.floor(idx / 10); const score = x * y;
                      let bgClass = "bg-emerald-50 border-emerald-100"; if (score >= 50) bgClass = "bg-red-50 border-red-100"; else if (score >= 20) bgClass = "bg-amber-50 border-amber-100";
                      const isSelected = matrixFilter?.s === x && matrixFilter?.o === y;
                      if (isSelected) bgClass = "bg-indigo-600 border-indigo-700 ring-2 ring-indigo-300 z-10 text-white";
                      const itemsInCell = data.filter(d => (d.severity || 0) === x && (d.occurrence || 0) === y);
                      return (<button key={idx} onClick={() => setMatrixFilter(isSelected ? null : {s:x, o:y})} className={`border rounded-sm relative group transition-all hover:scale-110 hover:z-20 outline-none flex items-center justify-center text-[10px] font-bold ${bgClass}`}>{itemsInCell.length > 0 ? itemsInCell.length : ''}</button>);
                   })}
                </div>
             </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col">
          <div className="mb-6">
            <h3 className="text-lg font-bold text-slate-800">{t.topRisks}</h3>
            <p className="text-sm text-slate-500 mt-1">{t.topRisksSubtitle}</p>
          </div>
          <div className="flex-1 min-h-[250px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={topRisksData} layout="vertical" margin={{ left: 10, right: 30 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#e2e8f0" />
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" width={120} tick={{fontSize: 11, fill: '#64748b'}} />
                <RechartsTooltip cursor={{fill: '#f1f5f9'}} contentStyle={{borderRadius: '8px', border: 'none'}} />
                <Bar dataKey="rpn" radius={[0, 4, 4, 0]} barSize={24} onClick={(d) => setBarFilter(barFilter === d.id ? null : d.id)}>
                  {topRisksData.map((entry, index) => <Cell key={index} fill={barFilter === entry.id ? '#4f46e5' : entry.rpn >= 120 ? '#ef4444' : '#f59e0b'} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Main Table Section */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden ring-1 ring-slate-900/5">
        <div className="p-6 border-b border-slate-200 flex flex-col xl:flex-row justify-between items-center gap-4 bg-slate-50/50">
          <div className="flex items-center gap-3"><div className="p-2 bg-indigo-600 rounded-lg"><FileText size={20} className="text-white" /></div><div><h3 className="text-lg font-bold text-slate-800">{t.details}</h3><p className="text-xs text-slate-500">{t.detailsSubtitle}</p></div></div>
          <div className="flex flex-wrap justify-center items-center gap-3">
            <button onClick={handleGenerateAllSheets} disabled={generatingSheets} className="flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 transition-all">
              {generatingSheets ? <Loader2 size={16} className="animate-spin" /> : <ClipboardList size={16} />}
              {generatingSheets ? `${progress.current}/${progress.total}` : t.genSheets}
            </button>
            <button onClick={handleCopy} className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-slate-700 bg-white hover:bg-slate-50 rounded-lg border border-slate-200 shadow-sm">
              {copied ? <CheckCircle size={16} className="text-green-600" /> : <Copy size={16} />} {t.flatCopy}
            </button>
            <button onClick={handleClassicalCopy} className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-indigo-700 bg-indigo-50 hover:bg-indigo-100 rounded-lg border border-indigo-200 shadow-sm">
              {classicalCopied ? <CheckCircle size={16} className="text-indigo-600" /> : <LayoutList size={16} />} {t.classicalCopy}
            </button>
          </div>
        </div>

        {/* Filters Info Bar */}
        {(matrixFilter || barFilter || searchFilters.component || searchFilters.failureMode) && (
           <div className="bg-slate-800 text-white px-6 py-3 flex justify-between items-center">
             <div className="flex items-center gap-3"><span className="text-sm font-medium flex items-center gap-1.5"><Filter size={14} />{t.activeFilters}</span></div>
             <button onClick={() => {setMatrixFilter(null); setBarFilter(null); setSearchFilters({component:'', failureMode:'', consequenceCategory:'', function:'', iso14224Code:''})}} className="text-xs bg-white text-slate-900 px-3 py-1.5 rounded font-bold hover:bg-slate-200">{t.clearFilters}</button>
           </div>
        )}

        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/80 border-b border-slate-200 text-[11px] font-bold uppercase tracking-wider text-slate-500 sticky top-0 z-10">
                <th className="px-6 py-4 min-w-[180px]">
                   <div className="flex flex-col gap-2">
                     <button onClick={() => requestSort('component')} className="flex items-center gap-1">{t.component} {renderSortIcon('component')}</button>
                     <input type="text" placeholder={t.searchPlaceholder} value={searchFilters.component} onChange={e => setSearchFilters({...searchFilters, component: e.target.value})} className="p-1 text-[10px] font-normal border rounded focus:ring-1 focus:ring-indigo-500 outline-none" />
                   </div>
                </th>
                <th className="px-6 py-4">{t.consequence}</th>
                <th className="px-6 py-4">{t.isoCode}</th>
                <th className="px-6 py-4 min-w-[200px]">
                   <div className="flex flex-col gap-2">
                     <button onClick={() => requestSort('failureMode')} className="flex items-center gap-1">{t.failureMode} {renderSortIcon('failureMode')}</button>
                     <input type="text" placeholder={t.searchPlaceholder} value={searchFilters.failureMode} onChange={e => setSearchFilters({...searchFilters, failureMode: e.target.value})} className="p-1 text-[10px] font-normal border rounded focus:ring-1 focus:ring-indigo-500 outline-none" />
                   </div>
                </th>
                <th className="px-6 py-4"><button onClick={() => requestSort('rpn')} className="flex items-center gap-1">{t.rpn} {renderSortIcon('rpn')}</button></th>
                <th className="px-6 py-4">{t.proposedTask}</th>
                <th className="px-6 py-4 text-center">{t.insp}</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm bg-white">
              {processedData.length === 0 ? (
                <tr><td colSpan={7} className="text-center py-20 text-slate-400 font-medium">{t.noMatches}</td></tr>
              ) : (
                processedData.map((item) => (
                  <tr key={item.id} className={`hover:bg-slate-50 transition-colors ${barFilter === item.id ? 'bg-indigo-50/50' : ''}`}>
                    <td className="px-6 py-4 font-medium text-xs">{item.component}</td>
                    <td className="px-6 py-4"><span className="text-[10px] font-bold px-1.5 py-0.5 rounded-full border bg-blue-50 text-blue-700">{item.consequenceCategory}</span></td>
                    <td className="px-6 py-4"><span className="text-[10px] font-mono font-bold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded border">{item.iso14224Code}</span></td>
                    <td className="px-6 py-4"><div className="font-semibold text-[11px] leading-tight">{item.failureMode}</div><div className="text-[10px] text-slate-400 line-clamp-1">{item.failureEffect}</div></td>
                    <td className="px-6 py-4 text-xs font-bold text-indigo-600">{item.rpn}</td>
                    <td className="px-6 py-4 text-xs">
                      <div className="font-medium">{item.maintenanceTask}</div>
                      <div className="text-[10px] text-slate-400 italic">{item.interval} • {item.taskType}</div>
                    </td>
                    <td className="px-6 py-4 text-center">
                      {item.inspectionSheet ? <CheckCircle size={18} className="text-emerald-500 mx-auto" /> : <File size={18} className="text-slate-300 mx-auto" />}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

