const getTaskImage = (task: string): string => {
  const t = (task || '').toLowerCase();
  if (t.includes('thermal') || t.includes('heat')) return 'https://images.unsplash.com/photo-1504917595217-d4dc5ebe6122?auto=format&fit=crop&w=800&q=80';
  if (t.includes('vibration') || t.includes('align')) return 'https://images.unsplash.com/photo-1581094288338-2314dddb7ece?auto=format&fit=crop&w=800&q=80';
  if (t.includes('oil') || t.includes('lubricat')) return 'https://images.unsplash.com/photo-1621905252507-b35492cc74b4?auto=format&fit=crop&w=800&q=80';
  return 'https://images.unsplash.com/photo-1565514020176-db5b550dd707?auto=format&fit=crop&w=800&q=80';
};

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

const getScoreColor = (score: number) => {
  if (score >= 8) return 'text-red-600 font-bold';
  if (score >= 5) return 'text-amber-600 font-medium';
  return 'text-slate-500';
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, onUpdate, onUndo, canUndo, language }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);
  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn'; direction: 'asc' | 'desc' }>({ key: 'rpn', direction: 'desc' });
  const [searchFilters, setSearchFilters] = useState({ component: '', function: '', failureMode: '', consequenceCategory: '', iso14224Code: '' });
  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);
  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());
  const [copied, setCopied] = useState(false);
  const [classicalCopied, setClassicalCopied] = useState(false);

  const t = translations[language] || translations.en;

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => !!item);
    if (matrixFilter) result = result.filter(item => (item.severity || 0) === matrixFilter.s && (item.occurrence || 0) === matrixFilter.o);
    if (barFilter) result = result.filter(item => item.id === barFilter);
    if (searchFilters.component) result = result.filter(item => item.component.toLowerCase().includes(searchFilters.component.toLowerCase()));
    if (searchFilters.failureMode) result = result.filter(item => item.failureMode.toLowerCase().includes(searchFilters.failureMode.toLowerCase()));

    result.sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;
      if (typeof aVal === 'string' && typeof bVal === 'string') return aVal.localeCompare(bVal) * multiplier;
      return ((aVal as number) - (bVal as number)) * multiplier;
    });
    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  const handleCopy = async () => {
    const headers = [t.component, t.consequence, t.isoCode, t.failureMode, t.rpn, t.proposedTask, t.frequency];
    const rows = processedData.map(item => [item.component, item.consequenceCategory, item.iso14224Code, item.failureMode, item.rpn, item.maintenanceTask, item.interval].join("\t"));
    await navigator.clipboard.writeText([headers.join("\t"), ...rows].join("\n"));
    setCopied(true); setTimeout(() => setCopied(false), 2000);
  };

  const handleClassicalCopy = async () => {
    const headers = [t.component, t.failureMode, t.proposedTask, t.frequency, t.type, t.stepsTitle, "Actions"];
    const rows: string[] = [];
    let lastComp = "";
    processedData.forEach(item => {
      const compVal = item.component === lastComp ? "" : item.component;
      lastComp = item.component;
      const steps = item.inspectionSheet?.steps || [{ step: 1, description: "" }];
      steps.forEach((s, idx) => {
        const row = [idx === 0 ? compVal : "", idx === 0 ? item.failureMode : "", idx === 0 ? item.maintenanceTask : "", idx === 0 ? item.interval : "", idx === 0 ? item.taskType : "", s.step, s.description];
        rows.push(row.map(v => String(v || '').replace(/\t/g, ' ')).join("\t"));
      });
    });
    await navigator.clipboard.writeText([headers.join("\t"), ...rows].join("\n"));
    setClassicalCopied(true); setTimeout(() => setClassicalCopied(false), 2000);
  };

  const handleGenerateAllSheets = async () => {
    const items = data.filter(item => !item.inspectionSheet);
    if (items.length === 0) return;
    setGeneratingSheets(true);
    setProgress({ current: 0, total: items.length });
    for (const item of items) {
      try {
        const sheet = await generateInspectionSheet(item, language);
        onUpdate(data.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d));
      } catch (e) {}
      setProgress(p => ({ ...p, current: p.current + 1 }));
    }
    setGeneratingSheets(false);
  };

  const stats = [
    { label: t.totalFailModes, value: data.length, icon: ListChecks, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: t.maxRPN, value: Math.max(...data.map(i => i.rpn || 0), 0), icon: AlertOctagon, color: 'text-red-600', bg: 'bg-red-50' },
    { label: t.conditionMonitoring, value: data.filter(i => i.taskType === 'Condition Monitoring').length, icon: Zap, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: t.timeBased, value: data.filter(i => i.taskType === 'Time-Based').length, icon: Clock, color: 'text-purple-600', bg: 'bg-purple-50' },
    { label: t.failureFinding, value: data.filter(i => i.taskType === 'Failure Finding').length, icon: Search, color: 'text-amber-600', bg: 'bg-amber-50' },
    { label: t.runToFailure, value: data.filter(i => i.taskType === 'Run-to-Failure').length, icon: CheckCircle, color: 'text-emerald-600', bg: 'bg-emerald-50' },
  ];

  return (
    <div className="space-y-8 animate-fade-in relative w-full">
      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-4">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
            <div className="flex flex-col gap-3">
              <div className={`w-10 h-10 rounded-xl ${stat.bg} ${stat.color} flex items-center justify-center shrink-0`}>
                <stat.icon size={20} />
              </div>
              <div>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-tight mb-1.5">{stat.label}</p>
                <h3 className="text-xl font-bold text-slate-800 leading-none">{stat.value}</h3>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
        <div className="xl:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800">{t.riskMatrix}</h3>
          <p className="text-sm text-slate-500 mt-1">{t.matrixSubtitle}</p>
          <div className="grid grid-cols-10 grid-rows-10 gap-1 mt-6 aspect-square w-full max-w-lg mx-auto">
            {Array.from({ length: 100 }).map((_, idx) => {
              const x = (idx % 10) + 1; const y = 10 - Math.floor(idx / 10);
              const items = data.filter(d => d.severity === x && d.occurrence === y);
              const isSelected = matrixFilter?.s === x && matrixFilter?.o === y;
              return (
                <button key={idx} onClick={() => setMatrixFilter(isSelected ? null : {s:x, o:y})} className={`border text-[10px] font-bold flex items-center justify-center rounded-sm transition-all ${isSelected ? 'bg-indigo-600 text-white border-indigo-700' : items.length > 0 ? 'bg-amber-100 text-amber-700' : 'bg-slate-50'}`}>
                  {items.length > 0 ? items.length : ''}
                </button>
              );
            })}
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800">{t.topRisks}</h3>
          <ResponsiveContainer width="100%" height={300} className="mt-6">
            <BarChart data={data.sort((a,b)=>b.rpn-a.rpn).slice(0,5)} layout="vertical">
              <XAxis type="number" hide />
              <YAxis dataKey="failureMode" type="category" width={100} tick={{fontSize: 10}} />
              <Bar dataKey="rpn" fill="#4f46e5" radius={[0, 4, 4, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-200 flex flex-col xl:flex-row justify-between items-center gap-4 bg-slate-50/50">
          <h3 className="text-lg font-bold text-slate-800 flex items-center gap-3"><FileText className="text-indigo-600" /> {t.details}</h3>
          <div className="flex flex-wrap gap-3">
            <button onClick={handleGenerateAllSheets} disabled={generatingSheets} className="flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg bg-indigo-600 text-white">
              {generatingSheets ? <Loader2 className="animate-spin" /> : <ClipboardList size={16} />} {t.genSheets}
            </button>
            <button onClick={handleCopy} className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-200 rounded-lg">
              <Copy size={16} /> {t.flatCopy}
            </button>
            <button onClick={handleClassicalCopy} className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-indigo-700 bg-indigo-50 border border-indigo-200 rounded-lg">
              <LayoutList size={16} /> {t.classicalCopy}
            </button>
          </div>
        </div>
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50/80 border-b border-slate-200 text-[11px] font-bold uppercase tracking-wider text-slate-500 sticky top-0">
              <tr>
                <th className="px-6 py-4">{t.component}</th>
                <th className="px-6 py-4">{t.consequence}</th>
                <th className="px-6 py-4">{t.isoCode}</th>
                <th className="px-6 py-4">{t.failureMode}</th>
                <th className="px-6 py-4">{t.rpn}</th>
                <th className="px-6 py-4">{t.proposedTask}</th>
                <th className="px-6 py-4 text-center">{t.insp}</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm bg-white">
              {processedData.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-medium text-xs">{item.component}</td>
                  <td className="px-6 py-4"><span className="text-[10px] font-bold px-1.5 py-0.5 rounded-full border bg-blue-50 text-blue-700">{item.consequenceCategory}</span></td>
                  <td className="px-6 py-4 text-[10px] font-mono">{item.iso14224Code}</td>
                  <td className="px-6 py-4 font-semibold text-[11px]">{item.failureMode}</td>
                  <td className="px-6 py-4 font-bold text-indigo-600">{item.rpn}</td>
                  <td className="px-6 py-4 text-xs">{item.maintenanceTask}</td>
                  <td className="px-6 py-4 text-center">
                    {item.inspectionSheet ? <CheckCircle size={18} className="text-emerald-500 mx-auto" /> : <File size={18} className="text-slate-300 mx-auto" />}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Language } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { 
  Cpu, Upload, Type, Zap, Loader2, FileCheck, Trash2, Menu, Save, Check, AlertTriangle, BookOpen, Sparkles, GitBranch, Undo2, Globe, X, ChevronRight
} from 'lucide-react';

const App: React.FC = () => {
  const [language, setLanguage] = useState<Language>(() => (localStorage.getItem('rcm_lang') as Language) || 'en');
  const [showIntro, setShowIntro] = useState(() => !localStorage.getItem('rcm_intro_seen'));
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<RCMItem[][]>([]);
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);

  useEffect(() => {
    localStorage.setItem('rcm_lang', language);
  }, [language]);

  const handleLanguageChange = (lang: Language) => {
    setLanguage(lang);
    setShowIntro(false);
    localStorage.setItem('rcm_intro_seen', 'true');
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) return;
    setIsLoading(true); setError(null); setResults(null); setHistory([]);
    try {
      const data = await generateRCMAnalysis(contextText, fileData, language);
      setResults(data);
    } catch (err: any) {
      setError(err.message || "An error occurred.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const last = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(last);
  };

  const handleSaveStudy = async () => {
    if (!results && !contextText) return;
    const study: SavedStudy = {
      id: currentStudyId || `study-${Date.now()}`,
      name: studyName,
      timestamp: Date.now(),
      items: results || [],
      contextText,
    };
    await saveStudyToDB(study);
    setJustSaved(true);
    setTimeout(() => setJustSaved(false), 2000);
    const updated = await getAllStudies();
    setSavedStudies(updated);
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setIsSidebarOpen(false);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-inter">
