      {showIntro && (
        <div className="fixed inset-0 z-[100] bg-slate-900/80 backdrop-blur-xl flex items-center justify-center p-6 animate-in fade-in duration-500">
          <div className="bg-white rounded-[3rem] shadow-2xl max-w-2xl w-full p-12 text-center space-y-8 animate-in zoom-in-95 duration-500 border border-white/20">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl mx-auto flex items-center justify-center text-white shadow-2xl shadow-indigo-100">
              <Cpu size={40} />
            </div>
            <div className="space-y-4">
              <h1 className="text-4xl font-black text-slate-900 tracking-tighter uppercase">RCM Generator Pro</h1>
              <p className="text-slate-500 font-medium leading-relaxed px-4">
                The world's most advanced AI-powered workstation for Reliability Centered Maintenance. 
                Generate SAE JA1011 compliant maintenance strategies, FMECA analyses, and inspection procedures in seconds.
              </p>
            </div>

            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Select Workspace Language</p>
              <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                {[
                  { code: 'en', label: 'English' },
                  { code: 'fr', label: 'Français' },
                  { code: 'es', label: 'Español' },
                  { code: 'de', label: 'Deutsch' },
                  { code: 'pl', label: 'Polski' }
                ].map(lang => (
                  <button
                    key={lang.code}
                    onClick={() => handleLanguageChange(lang.code as Language)}
                    className="p-4 border-2 border-slate-100 rounded-2xl hover:border-indigo-600 hover:bg-indigo-50 transition-all font-bold text-slate-700 text-sm flex flex-col items-center gap-1 group"
                  >
                    <span className="text-lg opacity-40 group-hover:opacity-100 transition-opacity uppercase">{lang.code}</span>
                    <span className="text-[10px]">{lang.label}</span>
                  </button>
                ))}
              </div>
            </div>
