                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl">
                  <Cpu size={22} className="text-indigo-400" />
                </div>
                <div className="flex flex-col">
                  <span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM PRO</span>
                  <span className="text-[10px] text-indigo-600 font-black uppercase tracking-widest mt-1">{language} Workspace</span>
                </div>
              </div>
              <input value={studyName} onChange={e => setStudyName(e.target.value)} className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent focus:border-indigo-500 outline-none w-64 hidden sm:block" />
            </div>

            <div className="flex items-center gap-4">
              {/* Language Switcher Dropdown */}
              <div className="relative group">
                <button className="flex items-center gap-2 p-2.5 bg-slate-50 text-slate-500 rounded-xl hover:bg-indigo-50 hover:text-indigo-600 transition-all border border-slate-100">
                  <Globe size={20} />
                  <span className="text-[10px] font-black uppercase">{language}</span>
                </button>
                <div className="absolute right-0 top-full mt-2 hidden group-hover:block bg-white rounded-2xl shadow-2xl border border-slate-100 p-2 min-w-[120px] z-[100]">
                  {['en', 'fr', 'es', 'de', 'pl'].map(l => (
                    <button key={l} onClick={() => setLanguage(l as Language)} className={`w-full text-left px-4 py-2 text-xs font-bold rounded-xl transition-colors ${language === l ? 'bg-indigo-600 text-white' : 'hover:bg-slate-50 text-slate-600'}`}>
                      {l.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>

              <button onClick={() => setShowSODReference(true)} className="p-2.5 text-slate-500 hover:bg-slate-50 rounded-xl"><BookOpen size={20} /></button>
              <button onClick={handleUndo} disabled={history.length === 0} className="p-2.5 bg-slate-50 text-slate-400 rounded-xl disabled:opacity-30"><Undo2 size={20} /></button>
              <button onClick={handleSaveStudy} className="bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-100 transition-all active:scale-95">
                {justSaved ? <Check size={18} /> : 'Save Study'}
              </button>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-6 bg-slate-50/50">
          {!results && (
            <div className="max-w-7xl mx-auto space-y-10 animate-in slide-in-from-bottom-4 duration-500">
              <div className="bg-white rounded-[2.5rem] p-10 border border-slate-200 shadow-sm space-y-6">
                <div className="flex items-center justify-between">
                  <h2 className="text-2xl font-black text-slate-900 tracking-tighter uppercase">Operational Context</h2>
                  <button onClick={() => setShowContextBuilder(true)} className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-600 rounded-xl text-xs font-black uppercase"><Sparkles size={16}/> Wizard</button>
                </div>
                <textarea value={contextText} onChange={e => setContextText(e.target.value)} className="w-full h-64 p-8 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-slate-800" placeholder="e.g., Centrifugal Pump P-101 is critical for line availability..." />
                <div className="flex justify-end">
                  <button onClick={handleGenerate} disabled={isLoading} className="bg-indigo-600 text-white px-12 py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-2xl hover:-translate-y-1 transition-all flex items-center gap-3">
                    {isLoading ? <Loader2 className="animate-spin" /> : <Zap size={18} />} {isLoading ? 'Generating Analysis...' : 'Initiate Synthesis'}
                  </button>
                </div>
              </div>
            </div>
          )}
          {results && <AnalysisResult data={results} onUpdate={setResults} onUndo={handleUndo} canUndo={history.length > 0} language={language} />}
        </main>
      </div>

      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={setContextText} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={setResults} />
    </div>
  );
};

export default App;
